  window.__DATA__ = window.__DATA__ || {};
  window.__DATA__["APPENDIX_DATA"] = {"sections":[{"title":"Python 基础过渡专项","content":[{"type":"paragraph","text":"本附录为 Python 基础薄弱的学习者提供快速过渡指南。假设你已有其他语言编程基础，目标是达到能独立阅读和编写 Agent 项目代码的水平。"},{"type":"callout","variant":"info","title":"学习建议","text":"如果你已有 Python 基础，可跳过本附录直接学习主线 6 章。预计 Python 基础过渡需要 2-3 周（有编程基础可压缩至 1-2 周）。"},{"type":"knowledgePoint","title":"变量与数据类型","content":[{"type":"code","data":{"filename":"python_basics.py","language":"python","title":"Python 基础语法速览","code":"import os\n# === 动态类型 ===\n# 第1步：动态类型演示 —— Python 变量无需声明类型，赋值即确定类型\n# 下面每行给变量赋不同类型的值，右侧已标注变量类型\n# 第1步：动态类型演示 —— Python 变量无需声明类型，赋值即确定类型\n# 下面每行给变量赋不同类型的值，右侧已标注变量类型\nname = \"Agent\"           # str\ncount = 42               # int\nprice = 9.99             # float\nactive = True            # bool\nitems = [1, 2, 3]        # list\ncfg = {\"key\": \"value\"}   # dict\n# 第2步：类型注解声明函数签名 —— 提升可读性，便于 IDE 静态检查\n\n# === 类型注解（推荐使用）===\n# 第2步：类型注解声明函数签名 —— 提升可读性，便于 IDE 静态检查\ndef greet(name: str, times: int = 1) -> str:\n    \"\"\"带类型注解的函数\"\"\"\n# 第3步：f-string 格式化 —— 在字符串中直接嵌入变量与表达式\n    return f\"Hello, {name}!\" * times\n\n# === f-string 格式化 ===\n# 第3步：f-string 格式化 —— 在字符串中直接嵌入变量与表达式\n# 第4步：列表推导式 —— 一行生成列表，比 for 循环更简洁高效\nversion = 3.12\nprint(f\"Python {version:.1f}\")  # Python 3.1\n\n# === 列表推导式 ===\n# 第5步：字典推导式 —— 一行构建 dict，常用于批量映射统计\n# 第4步：列表推导式 —— 一行生成列表，比 for 循环更简洁高效\nsquares = [x**2 for x in range(10) if x % 2 == 0]\n# [0, 4, 16, 36, 64]\n\n# === 字典推导式 ===\n# 第5步：字典推导式 —— 一行构建 dict，常用于批量映射统计\nword_len = {w: len(w) for w in [\"hello\", \"world\"]}\n# {'hello': 5, 'world': 5}","output":"Python 3.1\n[0, 4, 16, 36, 64]\n{'hello': 5, 'world': 5}"}}]},{"type":"knowledgePoint","title":"面向对象编程","content":[{"type":"code","data":{"filename":"oop_basics.py","language":"python","title":"Python OOP 核心概念","code":"import os\nfrom dataclasses import dataclass\nfrom typing import Optional\n\n# === dataclass：简化数据类定义 ===\n# 第1步：用 @dataclass 装饰器 —— 自动生成 __init__/__repr__，省去样板代码\n# 第1步：用 @dataclass 装饰器 —— 自动生成 __init__/__repr__，省去样板代码\n@dataclass\nclass Tool:\n    name: str\n    description: str\n    enabled: bool = True\n\n# 第2步：定义基类 BaseAgent —— 抽象出 Agent 的公共接口（模板方法）\n# === 继承 ===\n# 第2步：定义基类 BaseAgent —— 抽象出 Agent 的公共接口（模板方法）\nclass BaseAgent:\n    def __init__(self, name: str):\n        self.name = name\n    \n    def run(self, query: str) -> str:\n# 第3步：继承 BaseAgent 实现 ReActAgent —— 复用父类接口并扩展工具能力\n        raise NotImplementedError\n\n# 第4步：super().__init__ 复用父类构造 —— 避免重复初始化 name\n# 第3步：继承 BaseAgent 实现 ReActAgent —— 复用父类接口并扩展工具能力\nclass ReActAgent(BaseAgent):\n    def __init__(self, name: str, tools: list[Tool]):\n# 第5步：重写 run 方法 —— 子类提供具体行为，体现多态\n# 第4步：super().__init__ 复用父类构造 —— 避免重复初始化 name\n        super().__init__(name)\n        self.tools = tools\n    \n# 第6步：实现重试装饰器 —— 把失败重试逻辑与业务代码解耦\n# 第5步：重写 run 方法 —— 子类提供具体行为，体现多态\n    def run(self, query: str) -> str:\n        return f\"{self.name} processing: {query}\"\n\n# 第7步：循环发起调用并捕获异常 —— 未达上限则重试，达到则抛出\n# 这样临时故障也能自动恢复，提升 Agent 调用 LLM 的健壮性\n# === 装饰器 ===\n# 第6步：实现重试装饰器 —— 把失败重试逻辑与业务代码解耦\ndef retry(max_attempts: int = 3):\n    \"\"\"重试装饰器：Agent 开发常用\"\"\"\n    def decorator(func):\n        def wrapper(*args, **kwargs):\n# 第7步：循环发起调用并捕获异常 —— 未达上限则重试，达到则抛出\n# 这样临时故障也能自动恢复，提升 Agent 调用 LLM 的健壮性\n            for attempt in range(max_attempts):\n                try:\n# 第8步：用 @retry 装饰 call_llm —— 无需改函数体即获得重试能力\n                    return func(*args, **kwargs)\n                except Exception as e:\n                    if attempt == max_attempts - 1:\n                        raise\n                    print(f\"Attempt {attempt+1} failed: {e}\")\n        return wrapper\n# 第9步：实例化并调用 —— ReActAgent 组合 Tool，run 返回处理结果\n    return decorator\n\n# 第8步：用 @retry 装饰 call_llm —— 无需改函数体即获得重试能力\n@retry(max_attempts=3)\ndef call_llm(prompt: str) -> str:\n    \"\"\"带重试的 LLM 调用\"\"\"\n    return \"response\"\n\n# 使用\n# 第9步：实例化并调用 —— ReActAgent 组合 Tool，run 返回处理结果\nagent = ReActAgent(\"Assistant\", [Tool(\"search\", \"搜索\")])\nprint(agent.run(\"hello\"))","output":"Assistant processing: hello"}}]},{"type":"knowledgePoint","title":"异步编程（asyncio）","content":[{"type":"paragraph","text":"异步编程是 Agent 开发的核心技能——并发调用多个工具和 LLM API 能大幅提升性能。Python 使用 async/await 语法。"},{"type":"code","data":{"filename":"async_basics.py","language":"python","title":"asyncio 异步编程","highlightLines":[24,25],"code":"import os\nimport asyncio\nimport httpx\n\n# === async/await 基础 ===\n# 第1步：定义异步函数 async def —— 内部用 await 调用非阻塞 IO，不阻塞线程\n# 第1步：定义异步函数 async def —— 内部用 await 调用非阻塞 IO，不阻塞线程\nasync def call_llm(prompt: str) -> str:\n    \"\"\"异步调用 LLM API\"\"\"\n# 第2步：await 发起 HTTP 请求 —— 等待网络时让出控制权，提升并发能力\n# 请求体含 model 与 messages，messages 以 user 角色携带用户输入\n    async with httpx.AsyncClient() as client:\n# 第2步：await 发起 HTTP 请求 —— 等待网络时让出控制权，提升并发能力\n# 请求体含 model 与 messages，messages 以 user 角色携带用户输入\n        resp = await client.post(\"https://api.openai.com/v1/chat/completions\",\n                                 json={\"model\": \"gpt-5\", \"messages\": [{\"role\": \"user\", \"content\": prompt}]})\n# 第3步：定义并发函数 —— 一次性发起多个 LLM 调用，显著缩短总耗时\n        return resp.json()[\"choices\"][0][\"message\"][\"content\"]\n\n# === 并发执行多个任务 ===\n# 第3步：定义并发函数 —— 一次性发起多个 LLM 调用，显著缩短总耗时\n# 第4步：asyncio.gather 并发调度 —— 将多个协程打包同时执行，而非串行等待\n# 列表推导式先为每个 prompt 生成协程，*解包后交给 gather 并发运行\nasync def parallel_calls():\n    \"\"\"并发调用多个 LLM，大幅减少等待时间\"\"\"\n    prompts = [\"问题1\", \"问题2\", \"问题3\"]\n    # asyncio.gather 并发执行所有任务\n# 第5步：定义入口异步函数 —— 串联各步骤，作为程序主流程\n# 第4步：asyncio.gather 并发调度 —— 将多个协程打包同时执行，而非串行等待\n# 列表推导式先为每个 prompt 生成协程，*解包后交给 gather 并发运行\n    results = await asyncio.gather(*[call_llm(p) for p in prompts])\n    return results\n# 第6步：asyncio.run 启动事件循环 —— 运行入口协程，驱动全部异步任务\n\n# === 运行异步代码 ===\n# 第5步：定义入口异步函数 —— 串联各步骤，作为程序主流程\nasync def main():\n    results = await parallel_calls()\n    print(f\"获得 {len(results)} 个结果\")\n\n# 第6步：asyncio.run 启动事件循环 —— 运行入口协程，驱动全部异步任务\nasyncio.run(main())","output":"获得 3 个结果\n\n# 串行调用 3 个 LLM 约 3 秒\n# 并发调用 3 个 LLM 约 1 秒（3倍提速）","note":"asyncio.gather 是 Agent 并发调用工具的关键——将多个独立调用并行化"}}]},{"type":"knowledgePoint","title":"Pydantic 数据建模","content":[{"type":"paragraph","text":"Pydantic 是 Agent 开发中最重要的 Python 库之一——用于数据校验、LLM 输出解析、Tool Schema 生成。"},{"type":"code","data":{"filename":"pydantic_basics.py","language":"python","title":"Pydantic 数据建模","highlightLines":[14,17,20,22,23],"code":"import os\nfrom pydantic import BaseModel, Field, validator\nfrom typing import Optional\n\n# === 定义数据模型 ===\nclass AgentConfig(BaseModel):\n# 第1步：name 用 Field(...) 设为必填 —— ... 代表必填，不传则校验失败\n# 第1步：name 用 Field(...) 设为必填 —— ... 代表必填，不传则校验失败\n# 第2步：model 字段给默认值 gpt-5 —— 省略时使用默认模型\n    name: str = Field(..., description=\"Agent 名称\")\n# 第3步：temperature 用 ge/le 约束范围 —— 限定 0-2，越界立即报错\n# 第2步：model 字段给默认值 gpt-5 —— 省略时使用默认模型\n# 第4步：max_steps 限定 1-100 —— 防止步数配置异常导致死循环\n    model: str = Field(default=\"gpt-5\", description=\"使用的 LLM\")\n# 第5步：tools 用 default_factory=list —— 每次实例化得到独立空列表\n# 第3步：temperature 用 ge/le 约束范围 —— 限定 0-2，越界立即报错\n    temperature: float = Field(default=0.7, ge=0, le=2)  # 0-2 之间\n# 第6步：自定义校验器 @validator —— 对 name 做业务规则校验\n# 第4步：max_steps 限定 1-100 —— 防止步数配置异常导致死循环\n    max_steps: int = Field(default=10, ge=1, le=100)\n# 第5步：tools 用 default_factory=list —— 每次实例化得到独立空列表\n    tools: list[str] = Field(default_factory=list)\n    \n# 第6步：自定义校验器 @validator —— 对 name 做业务规则校验\n    @validator('name')\n# 第7步：实例化触发校验 —— 合法输入返回对象，非法立即抛错\n    def name_not_empty(cls, v):\n# 第8步：model_dump 转字典 —— 便于序列化存储或网络传输\n        if not v.strip():\n# 第9步：model_json_schema 生成 JSON Schema —— 可直接用于 Function Calling\n            raise ValueError('名称不能为空')\n        return v\n\n# 第10步：故意传入非法值 —— 验证 Pydantic 抛出的错误清晰可读\n# === 自动校验 ===\n# 第7步：实例化触发校验 —— 合法输入返回对象，非法立即抛错\nconfig = AgentConfig(name=\"MyAgent\", temperature=0.3)\n# 第8步：model_dump 转字典 —— 便于序列化存储或网络传输\nprint(config.model_dump())  # 转字典\n# 第9步：model_json_schema 生成 JSON Schema —— 可直接用于 Function Calling\nprint(config.model_json_schema())  # 生成 JSON Schema（用于 Function Calling）\n\n# === 校验失败抛出详细错误 ===\n# 第10步：故意传入非法值 —— 验证 Pydantic 抛出的错误清晰可读\ntry:\n    bad = AgentConfig(name=\"\", temperature=5.0)  # 两个字段都非法\nexcept Exception as e:\n    print(f\"校验失败: {e}\")","output":"{'name': 'MyAgent', 'model': 'gpt-5', 'temperature': 0.3, 'max_steps': 10, 'tools': []}\n\n校验失败: 2 validation errors for AgentConfig\n  name: 名称不能为空\n  temperature: ensure this value is less than or equal to 2","note":"Pydantic 自动生成 JSON Schema，可直接用于 OpenAI Function Calling 的工具定义"}}]},{"type":"knowledgePoint","title":"虚拟环境与包管理","content":[{"type":"code","data":{"filename":"venv_setup.sh","language":"bash","title":"Python 虚拟环境管理","code":"# === 创建虚拟环境 ===\n# 第1步：创建隔离的虚拟环境 .venv —— 避免污染系统 Python 与全局包\n# 第1步：创建隔离的虚拟环境 .venv —— 避免污染系统 Python 与全局包\npython3 -m venv .venv\n\n# 第2步：激活虚拟环境 —— 之后 pip 安装的包仅作用于当前项目\n# === 激活虚拟环境 ===\n# 第2步：激活虚拟环境 —— 之后 pip 安装的包仅作用于当前项目\nsource .venv/bin/activate    # macOS/Linux\n# .venv\\Scripts\\activate     # Windows\n# 第3步：安装 LLM 与 Agent 核心依赖 —— 这些是调用模型的基础库\n\n# === 安装 Agent 开发常用包 ===\n# 第3步：安装 LLM 与 Agent 核心依赖 —— 这些是调用模型的基础库\npip install openai anthropic    # LLM SDK\npip install pydantic            # 数据校验\npip install httpx               # 异步 HTTP\npip install tiktoken            # Token 计算\npip install langchain           # LangChain 框架\npip install langgraph           # LangGraph\npip install rich                # 终端美化\n# 第4步：导出已装依赖到 requirements.txt —— 便于他人复现环境\npip install jupyter             # Notebook\n\n# === 导出依赖 ===\n# 第5步：按清单安装依赖 —— 新机器一键还原相同环境\n# 第4步：导出已装依赖到 requirements.txt —— 便于他人复现环境\npip freeze > requirements.txt\n\n# 第6步：安装 uv 包管理器 —— 用 Rust 实现，安装速度远超 pip\n# === 安装依赖 ===\n# 第5步：按清单安装依赖 —— 新机器一键还原相同环境\npip install -r requirements.txt\n\n# === 推荐使用 uv（更快的包管理器）===\n# 第6步：安装 uv 包管理器 —— 用 Rust 实现，安装速度远超 pip\npip install uv\nuv pip install openai  # 比 pip 快 10-100 倍","output":"(虚拟环境创建并激活后，所有 pip install 只影响当前环境，不污染系统 Python)"}}]}]},{"title":"Python 进阶能力","content":[{"type":"paragraph","text":"掌握以下进阶能力后，你就能流畅阅读和编写 Agent 项目代码。"},{"type":"table","data":{"headers":["能力","重要性","在 Agent 开发中的用途"],"rows":[["**async/await 异步编程**","⭐⭐⭐⭐⭐","并发调用 LLM API 和工具，性能关键"],["**Pydantic 数据建模**","⭐⭐⭐⭐⭐","LLM 输出校验、Tool Schema 生成"],["**类型提示（Type Hints）**","⭐⭐⭐⭐","代码可读性、IDE 智能提示"],["**装饰器**","⭐⭐⭐⭐","重试、缓存、日志等横切关注点"],["**上下文管理器**","⭐⭐⭐","资源管理（API 客户端、文件句柄）"],["**生成器**","⭐⭐⭐","流式响应处理、惰性求值"],["**dataclass**","⭐⭐⭐","配置和数据结构定义"],["**functools**","⭐⭐","lru_cache 缓存、partial 偏函数"]]}},{"type":"callout","variant":"tip","title":"关键第三方库","text":"**openai/anthropic**: LLM SDK；**pydantic**: 数据校验；**httpx**: 异步 HTTP 客户端；**rich**: 终端美化输出；**tenacity**: 重试机制；**tiktoken**: Token 计算。这些是 Agent 开发的标配库。"}]},{"title":"推荐技术栈总览（Python 生态）","content":[{"type":"table","data":{"headers":["类别","推荐技术","用途","优先级"],"rows":[["**LLM SDK**","openai, anthropic","调用 GPT/Claude API","⭐⭐⭐⭐⭐"],["**数据校验**","pydantic v2","数据模型、输出校验、Schema 生成","⭐⭐⭐⭐⭐"],["**HTTP 客户端**","httpx","异步 HTTP 请求","⭐⭐⭐⭐⭐"],["**Token 计算**","tiktoken","精确计算 Token 数","⭐⭐⭐⭐"],["**重试机制**","tenacity","API 调用重试与退避","⭐⭐⭐⭐"],["**终端美化**","rich","彩色输出、进度条、表格","⭐⭐⭐"],["**CLI 工具**","typer","命令行界面开发","⭐⭐⭐"],["**Web 框架**","FastAPI","Agent 服务化","⭐⭐⭐⭐"],["**向量数据库**","ChromaDB, Qdrant","RAG 向量存储","⭐⭐⭐⭐"],["**Agent 框架**","LangChain, LangGraph","Agent 开发框架","⭐⭐⭐⭐⭐"],["**可观测性**","LangFuse, LangSmith","追踪、监控、评估","⭐⭐⭐⭐"],["**任务队列**","Celery + Redis","异步长任务","⭐⭐⭐"],["**容器化**","Docker","部署与隔离","⭐⭐⭐⭐"],["**代码沙箱**","E2B, Docker SDK","安全代码执行","⭐⭐⭐"]]}}]},{"title":"学习资源清单","content":[{"type":"paragraph","text":"以下是精心筛选的 Agent 开发学习资源，按类型分类。"},{"type":"knowledgePoint","title":"必读论文","content":[{"type":"list","ordered":false,"items":["**ReAct: Synergizing Reasoning and Acting in LLMs** (2022) - Agent 范式奠基","**Tree of Thoughts** (2023) - 多路径推理","**Reflexion** (2023) - 自我反思机制","**GraphRAG** (2024) - 知识图谱增强 RAG","**A Survey on LLM Agents** (2024) - Agent 综述"]}]},{"type":"knowledgePoint","title":"在线课程","content":[{"type":"list","ordered":false,"items":["**DeepLearning.AI** - ChatGPT Prompt Engineering for Developers（免费）","**DeepLearning.AI** - LangChain for LLM Application Development","**Anthropic** - Claude 官方文档与教程","**OpenAI** - Cookbook 实战示例库","**吴恩达** - Building Systems with the ChatGPT API"]}]},{"type":"knowledgePoint","title":"技术博客","content":[{"type":"list","ordered":false,"items":["**Anthropic Blog** - Building Effective Agents（必读）","**Lilian Weng** - LLM Powered Autonomous Agents（深度技术）","**LangChain Blog** - 框架最新动态","**OpenAI Cookbook** - 实战代码示例","**Hugging Face Blog** - 开源模型动态"]}]},{"type":"knowledgePoint","title":"活跃社区","content":[{"type":"list","ordered":false,"items":["**LangChain Discord** - 框架官方社区，问题解答快","**r/LocalLLaMA** (Reddit) - 开源模型讨论","**Hugging Face** - 模型和数据集","**GitHub Trending** - 跟踪热门 Agent 项目","**ArXiv** - 最新论文预印本"]}]}]}]};

