  window.__DATA__ = window.__DATA__ || {};
  window.__DATA__["CHAPTER_4_DATA"] = {"id":"ch4","number":4,"title":"多 Agent 系统设计","subtitle":"掌握多 Agent 协作架构，能设计复杂 Agent 系统","estimatedHours":15,"difficulty":4,"sections":[{"id":"4.1","title":"多 Agent 架构模式","subtitle":"掌握主流多 Agent 架构模式","estimatedMinutes":25,"difficulty":3,"objectives":["掌握中心化/去中心化架构","理解层级/扁平/网络/黑板模式","能根据场景选择架构"],"content":[{"type":"knowledgePoint","title":"四种多 Agent 架构模式","content":[{"type":"mermaid","data":{"title":"四种多 Agent 架构对比","code":"flowchart TB\n  subgraph 层级式\n    M1[Manager] --> W1[Worker1]\n    M1 --> W2[Worker2]\n    M1 --> W3[Worker3]\n  end\n  subgraph 扁平式\n    A1[Agent1] <--> A2[Agent2]\n    A2 <--> A3[Agent3]\n    A1 <--> A3[Agent3]\n  end\n  subgraph 网络式\n    N1[A1] <--> N2[A2]\n    N2 <--> N3[A3]\n    N3 <--> N4[A4]\n    N1 <--> N4\n    N1 <--> N3\n  end\n  subgraph 黑板模式\n    B[共享黑板] --> A1\n    B --> A2\n    B --> A3\n    A1 --> B\n    A2 --> B\n    A3 --> B\n  end"}},{"type":"table","data":{"headers":["模式","结构","优点","缺点","适用场景"],"rows":[["**层级式**","Manager-Worker","清晰可控、易调试","Manager 瓶颈","任务可分解的场景"],["**扁平式**","对等协作","灵活、无瓶颈","协调复杂","小规模协作"],["**网络式**","任意通信","最灵活","通信开销大、难追踪","复杂探索任务"],["**黑板模式**","共享状态","松耦合、易扩展","需维护一致性","知识共享场景"]]}},{"type":"callout","variant":"tip","title":"选型建议","text":"生产环境推荐**层级式**（可控性好）；探索性任务用**扁平式**（灵活）；需要共享大量中间结果用**黑板模式**。**网络式**通信复杂，谨慎使用。"}]}],"enterpriseCase":{"title":"层级式 Agent 客服系统","background":"某公司客服需处理售前/售后/物流/技术支持多种问题。","architecture":"Router Agent 分类问题 → 转接到 4 个专业 Agent → 结果汇总给 Router。","outcome":"问题路由准确率 92%，平均处理时间降低 50%。","lessons":"层级式架构的 Router 质量决定整体效果。"},"exercises":[{"title":"架构模式对比","description":"绘制 3 种架构模式对比图，分析各自优缺点。","hints":"关注可控性、灵活性、通信开销"}],"resources":[{"type":"paper","title":"AutoGen Multi-Agent 论文","url":"https://arxiv.org/abs/2308.08155"}],"quiz":["ch4-4.1-q1","ch4-4.1-q2"]},{"id":"4.2","title":"角色分工与设计","subtitle":"设计合理的 Agent 角色体系","estimatedMinutes":20,"difficulty":3,"objectives":["掌握常见 Agent 角色","能用 CrewAI 定义角色","理解角色边界划分"],"content":[{"type":"knowledgePoint","title":"常见 Agent 角色","content":[{"type":"table","data":{"headers":["角色","职责","典型工具","CrewAI 定义"],"rows":[["**Planner**","任务分解与规划","无/分析工具","Role='规划者' Goal='制定计划'"],["**Executor**","执行具体任务","代码/搜索/API","Role='执行者' Goal='完成任务'"],["**Reviewer**","审查结果质量","评估工具","Role='审查者' Goal='确保质量'"],["**Aggregator**","汇总多个结果","无/格式化工具","Role='聚合者' Goal='整合输出'"]]}},{"type":"code","data":{"filename":"crewai_roles.py","language":"python","title":"CrewAI 角色定义","highlightLines":[16,17,20,22,24,26,28,29,30,33,35,37],"code":"import os\nfrom crewai import Agent, Task, Crew\n\n# 定义角色\n# 第1步：定义规划角色 —— role/goal/backstory 共同描述一个 Agent 的人设，\n# 角色设定影响模型的行为定位，明确分工能减少输出漂移\nplanner = Agent(\n    # role 是角色名，决定模型自我定位的“身份”\n    role='项目规划者',\n    # goal 给出该角色要达成的目标，约束它产出的方向\n    goal='将用户需求分解为可执行的子任务',\n    # backstory 提供背景故事，让模型更贴合该身份说话与决策\n    backstory='你是经验丰富的项目经理，擅长任务分解和排期',\n    # llm 指定底层模型，可按角色重要性选不同档位以平衡成本\n    llm='gpt-5'\n)\n\n# 第2步：定义开发角色 —— 与规划者同理，专注“写代码”这一目标，\n# 不同 backstory 让各 Agent 行为稳定、互不串味\ncoder = Agent(\n    # role 标识开发者身份\n    role='Python 开发者',\n    # goal 约束其产出为高质量代码\n    goal='编写高质量的 Python 代码',\n    # backstory 让其代码风格稳定\n    backstory='你是 10 年经验的 Python 开发者，代码简洁高效',\n    # llm 指定所用模型\n    llm='gpt-5'\n)\n\n# 第3步：定义审查角色 —— 负责把关质量，形成“规划-开发-审查”的闭环，\n# 让前一个角色的输出被独立视角校验，降低错误遗漏\nreviewer = Agent(\n    # role 标识审查者身份\n    role='代码审查者',\n    # goal 明确审查目标\n    goal='确保代码质量和最佳实践',\n    # backstory 强调严格与安全视角\n    backstory='你是严格的代码审查专家，关注安全和性能',\n    # llm 指定所用模型\n    llm='gpt-5'\n)\n\n# 第4步：定义任务并串联上下文 —— Task 绑定执行角色，\n# context 把上游任务结果作为本任务的背景，形成信息依赖链\n# 定义任务\n# plan_task 由 planner 执行\nplan_task = Task(description='规划开发任务', agent=planner)\n# context 让编码任务能读到规划结果，避免重复理解需求\ncode_task = Task(description='编写代码', agent=coder, context=[plan_task])\n# 审查任务依赖编码结果，保证审的是刚写好的代码\nreview_task = Task(description='审查代码', agent=reviewer, context=[code_task])\n\n# 第5步：组建团队并执行 —— Crew 把角色与任务按依赖编排成流水线，\n# kickoff 触发整队协作，自动按 context 顺序逐步推进到出结果\n# 组建团队\n# 把三个角色与三个任务组装成 Crew\ncrew = Crew(agents=[planner, coder, reviewer], tasks=[plan_task, code_task, review_task])\n# kickoff 启动协作并输出最终结果\nresult = crew.kickoff('开发一个计算器程序')","output":"规划者: 分解为3个子任务\n开发者: 编写 calculator.py\n审查者: 代码质量8/10，建议增加异常处理"}}]}],"enterpriseCase":{"title":"软件开发团队 Agent 化","background":"用多 Agent 模拟软件开发团队：PM/设计/前端/后端/测试。","architecture":"CrewAI 定义 5 个角色，PM 分解需求 → 前后端并行开发 → 测试 Agent 验证。","outcome":"小型项目自动开发成功率 70%，开发时间缩短 60%。","lessons":"角色定义要明确边界，避免职责重叠。"},"exercises":[{"title":"设计 Agent 角色","description":"为一个数据分析项目设计 4 个 Agent 角色。","hints":"考虑数据收集/清洗/分析/报告四个环节"}],"resources":[{"type":"doc","title":"CrewAI 文档","url":"https://docs.crewai.com/"}],"quiz":[]},{"id":"4.3","title":"Agent 间通信协议","subtitle":"掌握 Agent 通信机制","estimatedMinutes":25,"difficulty":3,"objectives":["理解消息传递模式","掌握共享状态 vs 消息传递","了解 LangGraph/AutoGen 通信"],"content":[{"type":"knowledgePoint","title":"通信模式对比","content":[{"type":"table","data":{"headers":["模式","原理","优点","缺点"],"rows":[["**共享状态**","Agent 读写公共状态对象","简单直接、易调试","并发控制复杂"],["**消息传递**","Agent 间发送结构化消息","松耦合、可扩展","消息路由复杂"],["**群聊模式**","所有 Agent 在同一对话中","自然协作、AutoGen 风格","Token 消耗大"],["**事件驱动**","发布订阅事件","异步解耦","时序难保证"]]}},{"type":"code","data":{"filename":"multi_agent_comm.py","language":"python","title":"LangGraph 共享状态多 Agent","code":"import os\nfrom langgraph.graph import StateGraph, END\nfrom typing import TypedDict, Annotated\nimport operator\n\n# 第1步：定义共享状态 —— TypedDict 描述团队各成员要写入的字段，\n# 所有 Agent 读写同一份状态而非互相传参，协作关系更清晰\nclass TeamState(TypedDict):\n    task: str\n    research_result: str\n    code_result: str\n    review_result: str\n    final_output: str\n\n# 第2步：研究 Agent —— 从共享状态读任务、写研究结果，\n# 每个节点只更新自己负责的字段，互不干扰也便于并行\ndef researcher(state: TeamState) -> dict:\n    # 研究 Agent：共享状态中读取任务，写入研究结果\n    # 把任务拼进研究结果\n    result = f\"关于 {state['task']} 的研究结果\"\n    # 写入 research_result 字段\n    return {\"research_result\": result}\n\n# 第3步：编码 Agent —— 读取研究结果产出代码，\n# 依赖上一个节点的输出，保证实现基于已确认的方案\ndef coder(state: TeamState) -> dict:\n    # 编码 Agent：读取研究结果，写入代码\n    # 基于研究结果生成代码\n    code = f\"基于 {state['research_result']} 编写代码\"\n    # 写入 code_result 字段\n    return {\"code_result\": code}\n\n# 第4步：审查 Agent —— 读代码给出结论并写最终输出，\n# 作为流水线的最后一环，把结果沉淀到 final_output\ndef reviewer(state: TeamState) -> dict:\n    # 审查 Agent：读取代码，写入审查结果\n    # 生成审查结论\n    review = f\"代码审查: {state['code_result']} → 通过\"\n    # 写回审查结果与最终输出\n    return {\"review_result\": review, \"final_output\": review}\n\n# 第5步：用状态图串起协作 —— StateGraph 把三个 Agent 编排成有向流程，\n# 比手写调度更直观，新增成员只需加节点和边\n# 共享状态图\ngraph = StateGraph(TeamState)\ngraph.add_node(\"researcher\", researcher)\ngraph.add_node(\"coder\", coder)\ngraph.add_node(\"reviewer\", reviewer)\ngraph.set_entry_point(\"researcher\")\ngraph.add_edge(\"researcher\", \"coder\")\ngraph.add_edge(\"coder\", \"reviewer\")\ngraph.add_edge(\"reviewer\", END)\n\n# 第6步：编译运行 —— compile 生成可执行图，invoke 传入初始任务即触发全流程\napp = graph.compile()\n# 传入任务并获取最终结果\nresult = app.invoke({\"task\": \"开发计算器\"})","output":"research_result: 关于 开发计算器 的研究结果\ncode_result: 基于 研究结果 编写代码\nreview_result: 代码审查: 代码 → 通过"}}]}],"enterpriseCase":{"title":"多 Agent 协作消息流","background":"某报告生成系统需要研究/分析/撰写三个 Agent 协作。","architecture":"用 LangGraph 共享状态传递中间结果，每个 Agent 负责一个环节。","outcome":"报告生成全自动化，质量评分 4.2/5。","lessons":"共享状态适合线性流程，复杂交互用消息传递。"},"exercises":[{"title":"实现 Agent 通信","description":"用 LangGraph 实现两个 Agent 的共享状态通信。","hints":"用 TypedDict 定义共享状态"}],"resources":[{"type":"doc","title":"LangGraph Multi-Agent","url":"https://langchain-ai.github.io/langgraph/tutorials/multi_agent/"}],"quiz":[]},{"id":"4.4","title":"任务分解与编排","subtitle":"设计任务分解策略与编排方案","estimatedMinutes":30,"difficulty":4,"objectives":["掌握任务分解策略","理解 DAG 编排","能用 LangGraph 实现 DAG"],"content":[{"type":"knowledgePoint","title":"任务分解策略","content":[{"type":"table","data":{"headers":["策略","原理","适用场景"],"rows":[["**按功能分解**","按能力域划分（研究/编码/测试）","角色明确的场景"],["**按阶段分解**","按时间顺序（收集/处理/输出）","流水线任务"],["**按数据分解**","按数据分片（每 Agent 处理一部分）","大规模数据处理"],["**按复杂度分解**","简单/复杂任务分给不同 Agent","性能优化场景"]]}},{"type":"callout","variant":"warning","title":"分解粒度","text":"太粗（2-3个任务）：并行度低，单任务复杂；太细（20+任务）：编排开销大，通信成本高。经验值：5-10 个子任务最优。"}]},{"type":"knowledgePoint","title":"DAG 编排实现","content":[{"type":"code","data":{"filename":"dag_orchestration.py","language":"python","title":"LangGraph DAG 并行编排","highlightLines":[28,31,32,33,34,35,36,37],"code":"import os\nfrom langgraph.graph import StateGraph, END\nfrom typing import TypedDict\n\n# 第1步：定义报告状态 —— 各采集与加工环节的结果都放进共享状态，\n# 后续节点按需读取，避免重复计算也方便做 DAG 依赖\nclass ReportState(TypedDict):\n    topic: str\n    market_data: str\n    tech_data: str\n    finance_data: str\n    analysis: str\n    report: str\n\n# 第2步：并行采集节点 —— 三个函数各自只取自己负责的字段，\n# 彼此无依赖，所以后面能让它们同时跑以缩短总耗时\ndef collect_market(state): return {\"market_data\": \"市场数据\"}\ndef collect_tech(state): return {\"tech_data\": \"技术数据\"}\ndef collect_finance(state): return {\"finance_data\": \"财务数据\"}\n# 第3步：汇总分析节点 —— 等三类数据齐了再综合，\n# 放在并行采集之后，确保输入完整、结论才可靠\ndef analyze(state): \n    return {\"analysis\": f\"综合分析: {state['market_data']}+{state['tech_data']}+{state['finance_data']}\"}\n# 第4步：生成报告节点 —— 基于分析结果落稿，\n# 是 DAG 的末端，产出最终交付物\ndef write_report(state): \n    return {\"report\": f\"报告: {state['analysis']}\"}\n\n# 第5步：搭建 DAG 图 —— StateGraph 把节点连成有向无环图，\n# 明确的边即依赖关系，框架据此决定哪些节点可并行\n# DAG: 三个收集任务并行 → 分析 → 报告\ngraph = StateGraph(ReportState)\ngraph.add_node(\"market\", collect_market)\ngraph.add_node(\"tech\", collect_tech)\ngraph.add_node(\"finance\", collect_finance)\ngraph.add_node(\"analyze\", analyze)\ngraph.add_node(\"report\", write_report)\n\n# 第6步：声明并行入口 —— 让 market/tech/finance 都指向 analyze，\n# 框架检测到三者无前后依赖便会并发执行，最后汇聚到分析\n# 并行收集\ngraph.set_entry_point(\"market\")\ngraph.add_edge(\"market\", \"analyze\")\ngraph.add_edge(\"tech\", \"analyze\")\ngraph.add_edge(\"finance\", \"analyze\")\n# 串行后处理：分析之后顺序生成报告\n# 串行后处理\ngraph.add_edge(\"analyze\", \"report\")\ngraph.add_edge(\"report\", END)\n\n# 第7步：编译运行 —— compile 把 DAG 变成可执行应用，\n# invoke 传入主题即触发“并行采集→分析→报告”全流程\napp = graph.compile()\nresult = app.invoke({\"topic\": \"AI行业分析\"})","output":"market, tech, finance 三个任务并行执行\n→ analyze 汇总三方面数据\n→ report 生成最终报告"}}]}],"enterpriseCase":{"title":"自动化报告生成 Agent","background":"某咨询公司需生成行业分析报告，包含市场/技术/财务三维度。","architecture":"DAG 编排：3 个收集 Agent 并行 → 分析 Agent 汇总 → 报告 Agent 生成。","outcome":"报告生成时间从 4 小时降至 20 分钟。","lessons":"DAG 并行化是多 Agent 系统性能优化的关键。"},"exercises":[{"title":"设计 DAG 编排","description":"为一个数据分析任务设计 DAG 编排图。","hints":"识别可并行的任务和有依赖的任务"}],"resources":[{"type":"doc","title":"LangGraph 复杂工作流","url":"https://langchain-ai.github.io/langgraph/"}],"quiz":["ch4-4.4-q1"]},{"id":"4.5","title":"结果聚合与冲突解决","subtitle":"掌握多 Agent 结果融合策略","estimatedMinutes":20,"difficulty":3,"objectives":["掌握聚合策略","理解冲突解决机制","能设计审查 Agent"],"content":[{"type":"knowledgePoint","title":"聚合策略","content":[{"type":"table","data":{"headers":["策略","原理","适用场景"],"rows":[["**投票**","多数票决定","分类/判断任务"],["**加权**","按 Agent 权重加权","Agent 能力差异大"],["**层级审查**","Critic Agent 审查所有结果","质量要求高"],["**LLM 聚合**","用 LLM 综合多个结果","生成型任务"]]}},{"type":"callout","variant":"info","title":"Multi-Agent Debate","text":"让多个 Agent 对同一问题给出不同答案，然后辩论并达成共识。研究表明这能提升推理质量，但 Token 消耗大。"}]}],"enterpriseCase":{"title":"多 Agent 代码审查","background":"用 3 个 Agent 从安全/性能/可读性审查同一份代码。","architecture":"3 个专业 Agent 并行审查 → Critic Agent 聚合，冲突时取最严格建议。","outcome":"代码缺陷发现率提升 40%。","lessons":"多视角审查比单 Agent 更全面。"},"exercises":[{"title":"设计投票聚合","description":"实现一个简单的多 Agent 投票聚合机制。","hints":"用 collections.Counter 统计票数"}],"resources":[{"type":"paper","title":"Multi-Agent Debate","url":"https://arxiv.org/abs/2305.14325"}],"quiz":[]},{"id":"4.6","title":"长任务编排与状态管理","subtitle":"管理长时间运行的多 Agent 任务","estimatedMinutes":25,"difficulty":4,"objectives":["理解长任务挑战","掌握 Checkpoint 机制","能实现状态恢复"],"content":[{"type":"knowledgePoint","title":"长任务挑战与方案","content":[{"type":"table","data":{"headers":["挑战","方案"],"rows":[["状态持久化","LangGraph Checkpoint / 数据库"],["中断恢复","保存中间状态，可从断点继续"],["资源管理","Celery + Redis 异步队列"],["进度追踪","状态机 + 可观测性"],["失败恢复","补偿事务 + 重试"]]}},{"type":"code","data":{"filename":"long_task.py","language":"python","title":"LangGraph Checkpoint 持久化","highlightLines":[16,17,20,22],"code":"import os\nfrom langgraph.graph import StateGraph\nfrom langgraph.checkpoint.memory import MemorySaver\n# 生产环境用: from langgraph.checkpoint.postgres import PostgresSaver\n\n# 第1步：定义任务状态 —— 记录当前步骤、输入数据与中间结果列表，\n# 配合检查点即可在任意步暂停、恢复，适合耗时长的任务\nclass TaskState(TypedDict):\n    step: int\n    data: str\n    results: list\n\n# 第2步：创建状态图 —— 先建图骨架，节点随后补，\n# 这里用占位注释表示“在此注册各处理节点”\ngraph = StateGraph(TaskState)\n# ... 添加节点 ...\n\n# 第3步：接入检查点 —— MemorySaver 在每步执行后自动持久化状态，\n# 进程中断也能凭 thread_id 找回进度，不必从头再跑\n# 添加 Checkpoint：每步自动保存状态\n# 创建内存检查点实例\ncheckpointer = MemorySaver()\n# 第4步：编译时挂上检查点 —— compile 把检查点注入运行时的状态读写，\n# 之后每次 invoke 都会先落盘再继续，天然支持断点续跑\napp = graph.compile(checkpointer=checkpointer)\n\n# 第5步：带 thread_id 执行 —— config 里的 thread_id 唯一标识这次会话，\n# 它是恢复进度的“钥匙”，不同任务要用不同 id 以免串状态\n# 执行（带 thread_id 用于恢复）\n# 用唯一 thread_id 标识本次任务\nconfig = {\"configurable\": {\"thread_id\": \"task-001\"}}\n# 带配置执行，状态按 thread_id 自动保存\nresult = app.invoke({\"step\": 0, \"data\": \"input\", \"results\": []}, config)\n\n# 中断后可用同一 thread_id 恢复，无需重跑\n# 中断后可从上次状态恢复\n# result = app.invoke(None, config)  # 继续执行","output":"任务 task-001 执行到第3步保存\n→ 可从第3步恢复继续执行"}}]}],"enterpriseCase":{"title":"长周期数据分析 Agent","background":"某公司需要 Agent 处理数小时的数据分析任务。","architecture":"Celery + Redis 任务队列，LangGraph Checkpoint 持久化，支持中断恢复。","outcome":"长任务成功率从 60% 提升至 95%（可恢复）。","lessons":"长任务必须支持 Checkpoint，否则中断后从头重来浪费巨大。"},"exercises":[{"title":"实现 Checkpoint","description":"用 LangGraph MemorySaver 实现任务状态保存和恢复。","hints":"用 thread_id 关联任务"}],"resources":[{"type":"doc","title":"LangGraph Persistence","url":"https://langchain-ai.github.io/langgraph/concepts/persistence/"},{"type":"doc","title":"Celery 文档","url":"https://docs.celeryq.dev/"}],"quiz":[]},{"id":"4.7","title":"Human-in-the-Loop 设计","subtitle":"设计人工介入流程","estimatedMinutes":20,"difficulty":3,"objectives":["理解 HITL 价值","掌握 LangGraph interrupt 机制","能设计人工审批节点"],"content":[{"type":"knowledgePoint","title":"HITL 实现方式","content":[{"type":"paragraph","text":"HITL 在关键决策点暂停 Agent 执行，等待人工输入后继续。LangGraph 提供 `interrupt` 机制实现优雅的 HITL。"},{"type":"code","data":{"filename":"hitl_langgraph.py","language":"python","title":"LangGraph HITL 实现","highlightLines":[20,22,24],"code":"import os\nfrom langgraph.graph import StateGraph, END\nfrom langgraph.checkpoint.memory import MemorySaver\n\n# 第1步：定义审批状态 —— 记录请求内容、金额与是否通过，\n# 状态贯穿“审核-人工确认-执行”全过程，人工节点也能读写\nclass ApproveState(TypedDict):\n    request: str\n    amount: float\n    approved: bool\n\n# 第2步：审核节点 —— 先判断是否触发人工审批，\n# 阈值以下自动放行，以上才打断等待人确认，平衡效率与安全\ndef review_request(state):\n    # 检查是否需要人工审批\n    if state[\"amount\"] > 5000:\n        # HITL: 暂停等待人工输入\n        # 第3步：发起人工打断 —— interrupt 把控制权交还调用方并暂停图，\n        # 传入待确认信息，直到外部 resume 才继续，实现人在回路\n        human_decision = interrupt({  # LangGraph interrupt\n            # 标记这是审批类型，方便前端决定展示什么界面\n            \"type\": \"approval\",\n            # 把金额与原因告诉审核人，信息充分才好决策\n            \"message\": f\"金额 ${state['amount']} 超过阈值，需要审批\",\n            \"request\": state[\"request\"]\n        })\n        # 用人工的决定更新审批结果\n        return {\"approved\": human_decision[\"approved\"]}\n    return {\"approved\": True}  # 小额自动通过\n\n# 第4步：执行节点 —— 依据 approved 决定真正落地还是拒绝，\n# 把“决策”与“执行”分开，人可在执行前最后拦截\ndef execute(state):\n    if state[\"approved\"]:\n        return {\"result\": \"执行成功\"}\n    return {\"result\": \"已拒绝\"}\n\n# 第5步：组装并编译图 —— 在 execute 前插入 interrupt_before 断点，\n# 即使代码里没 interrupt，也能在节点边界暂停等人确认，双重保险\ngraph = StateGraph(ApproveState)\ngraph.add_node(\"review\", review_request)\ngraph.add_node(\"execute\", execute)\ngraph.set_entry_point(\"review\")\ngraph.add_edge(\"review\", \"execute\")\ngraph.add_edge(\"execute\", END)\n\n# 编译并在 execute 前设断点，待人确认后再执行\napp = graph.compile(checkpointer=MemorySaver(), interrupt_before=[\"execute\"])","output":"金额 $3000 → 自动通过\n金额 $8000 → 暂停，等待人工审批\n  人工批准 → 继续执行\n  人工拒绝 → 终止"}}]},{"type":"callout","variant":"tip","title":"HITL 关键场景","text":"1) **金融交易**：金额超过阈值；2) **数据删除**：不可逆操作；3) **外部发送**：邮件/消息发送；4) **代码部署**：生产环境变更。这些场景必须 HITL。"}],"enterpriseCase":{"title":"金融交易 Agent 审批","background":"某银行自动交易 Agent 需要在大额交易时人工确认。","architecture":"LangGraph interrupt + 异步 Webhook 通知审批人，审批后通过 Command 恢复执行。","outcome":"大额交易 100% 人工确认，零未授权交易。","lessons":"HITL 是金融场景的合规必需品。"},"exercises":[{"title":"实现 HITL 工作流","description":"用 LangGraph 实现一个带人工确认节点的 Agent 工作流。","hints":"用 interrupt_before 或 interrupt 函数"}],"resources":[{"type":"doc","title":"LangGraph HITL","url":"https://langchain-ai.github.io/langgraph/concepts/human_in_the_loop/"}],"quiz":["ch4-4.7-q1"]},{"id":"4.8","title":"Computer Use 与浏览器自动化","subtitle":"Agent 操作 GUI 的能力","estimatedMinutes":25,"difficulty":4,"objectives":["理解 Computer Use 概念","掌握 Playwright 自动化","了解 GUI 操作挑战"],"content":[{"type":"knowledgePoint","title":"Computer Use 概述","content":[{"type":"paragraph","text":"**Computer Use** 是 Anthropic 推出的 Agent 操作图形界面能力——Agent 通过截图理解屏幕内容，通过鼠标键盘操作软件。这是 Agent 从 API 世界走向 GUI 世界的里程碑。"},{"type":"table","data":{"headers":["方案","原理","优点","缺点"],"rows":[["**Anthropic Computer Use**","截图+视觉理解+鼠标键盘","通用性强、能操作任意软件","速度慢、可靠性待提升"],["**Playwright**","DOM 操作+选择器","快速可靠、代码可控","仅限网页、需适配 UI 变化"],["**RPA（UiPath）**","录屏回放","成熟稳定","固定流程、无自主性"],["**纯 API 调用**","直接调用 API","最快最可靠","需要 API 支持"]]}},{"type":"callout","variant":"warning","title":"GUI vs API","text":"能用 API 就不要用 GUI。GUI 自动化速度慢、脆弱（UI 改版即失效）、成本高（每次截图都消耗 Token）。Computer Use 适合没有 API 的遗留系统。"}]},{"type":"knowledgePoint","title":"Playwright 浏览器自动化","content":[{"type":"code","data":{"filename":"playwright_agent.py","language":"python","title":"Playwright 网页操作 Agent","highlightLines":[20,23,25,27,28,31,32],"code":"import os\nfrom playwright.sync_api import sync_playwright\n\n# 第1步：定义网页 Agent 函数 —— 传入自然语言任务，返回页面最终结果，\n# 用同步 API 更易读，适合脚本式的一次性自动化\ndef web_agent(task: str):\n    \"\"\"用 Playwright 实现网页操作 Agent\"\"\"\n    # 第2步：进入 Playwright 上下文 —— with 块自动管理浏览器生命周期，\n    # 退出时释放资源，避免进程残留占用端口\n    with sync_playwright() as p:\n        # 启动 Chromium，headless=False 可见便于调试\n        browser = p.chromium.launch(headless=False)\n        # 开一个新标签页，后续操作都在这个页面上进行\n        page = browser.new_page()\n        \n        # 第3步：打开目标网址 —— 先到页面才能截图与交互，\n        # 这里用示例站占位，真实场景换成任务指定的地址\n        # 1. 导航到目标页面\n        page.goto(\"https://example.com\")\n        \n        # 第4步：截图交给 LLM 决策 —— 把页面视觉信息传模型，\n        # 由它判断该点哪、填什么，让 Agent 具备“看懂页面”的能力\n        # 2. 理解页面（截图给 LLM 分析）\n        # 截图保存当前页面图像\n        screenshot = page.screenshot()\n        # LLM 返回操作序列；llm_analyze 为示意函数，需自行实现\n        actions = llm_analyze(task, screenshot)  # LLM 决定操作\n        \n        # 第5步：按 LLM 指令逐步执行 —— 遍历动作列表分支处理各类操作，\n        # 点击、输入、等待分别映射到对应 API，覆盖常见交互\n        # 3. 执行操作\n        for action in actions:\n            if action[\"type\"] == \"click\":\n                page.click(action[\"selector\"])\n            elif action[\"type\"] == \"type\":\n                page.fill(action[\"selector\"], action[\"text\"])\n            elif action[\"type\"] == \"wait\":\n                page.wait_for_timeout(action[\"ms\"])\n        \n        # 4. 获取结果\n        # 第6步：取回页面内容并收尾 —— 拿到渲染后的 HTML 作为结果，\n        # 关闭浏览器释放资源，把结果返回给调用方\n        result = page.content()\n        browser.close()\n        # 返回页面最终内容\n        return result","output":"Agent 任务: 在网站搜索商品\n→ 截图分析页面结构\n→ 点击搜索框 → 输入关键词 → 点击搜索按钮\n→ 获取搜索结果"}}]}],"enterpriseCase":{"title":"自动化测试 Agent","background":"某公司需要 Agent 自动测试 Web 应用的 UI。","architecture":"Agent 用 Playwright 操作浏览器，截图理解页面，自主执行测试用例。","outcome":"UI 测试覆盖率从 40% 提升至 85%，测试时间缩短 70%。","lessons":"Playwright + LLM 是 GUI 自动化的最佳实践，比纯 Computer Use 更可靠。"},"exercises":[{"title":"实现网页操作 Agent","description":"用 Playwright 实现一个能自动填表单的 Agent。","hints":"用 page.fill 和 page.click"}],"resources":[{"type":"doc","title":"Anthropic Computer Use","url":"https://docs.anthropic.com/en/docs/build-with-claude/computer-use"},{"type":"doc","title":"Playwright Python","url":"https://playwright.dev/python/"}],"quiz":[]}]};

