  window.__DATA__["CHAPTER_5_DATA"] = {"id":"ch5","number":5,"title":"行业应用与最佳实践","subtitle":"通过企业级实战项目巩固所学，掌握部署与工程化","estimatedHours":25,"difficulty":4,"sections":[{"id":"5.1","title":"智能客服系统","subtitle":"设计生产级客服 Agent","estimatedMinutes":35,"difficulty":3,"objectives":["掌握多轮对话管理","实现知识库集成","设计人工转接策略"],"content":[{"type":"knowledgePoint","title":"智能客服架构","content":[{"type":"mermaid","data":{"title":"智能客服系统架构","code":"flowchart TB\n  U[用户消息] --> R[意图识别 Router]\n  R -->|售前咨询| A1[商品知识库 RAG]\n  R -->|售后问题| A2[订单系统查询]\n  R -->|物流查询| A3[物流 API]\n  R -->|投诉/复杂| A4[转人工]\n  A1 --> G[回答生成]\n  A2 --> G\n  A3 --> G\n  G --> U2[回复用户]\n  A4 --> H[人工客服]"}},{"type":"code","data":{"filename":"customer_service.py","language":"python","title":"智能客服 Agent 完整架构","highlightLines":[28,30,32,33,36,37,39,41,43,45,46,47],"code":"# ===== 依赖与导入 =====\n# 引入 OpenAI 客户端、类型标注与数据校验工具\nimport os\nfrom openai import OpenAI\nfrom typing import Literal\nfrom pydantic import BaseModel\n\n# ===================== 配置区（请自行填写，或设置环境变量）=====================\n# 方式一（推荐）：在终端先设置环境变量，再运行本脚本\n#   export OPENAI_API_KEY=\"sk-你的密钥\"\n#   export OPENAI_BASE_URL=\"https://api.openai.com/v1\"   # 官方地址，或任意兼容 OpenAI 的中转地址\n#   export OPENAI_MODEL=\"gpt-4o\"\n# 方式二（仅本地测试，切勿提交到 Git）：直接把下面的值改成你的真实信息\n# 第1步：加载配置 —— 优先读环境变量，避免密钥硬编码进代码\n# 缺失时回退占位值，保证脚本先能跑通再填真实信息\nOPENAI_API_KEY = os.getenv(\"OPENAI_API_KEY\", \"sk-在此填入你的API密钥\")\nOPENAI_BASE_URL = os.getenv(\"OPENAI_BASE_URL\", \"https://api.openai.com/v1\")\nMODEL = os.getenv(\"OPENAI_MODEL\", \"gpt-4o-mini\")  # ← 模型名称，按需替换（如 gpt-4o-mini）\n\n\n# 第2步：创建 OpenAI 客户端 —— 复用同一实例发请求，省去重复初始化\n# base_url 支持官方或兼容中转，方便切换不同供应商\nclient = OpenAI(api_key=OPENAI_API_KEY, base_url=OPENAI_BASE_URL)\n\n# ===== 意图分类模型 =====\n# 用 Pydantic 约束输出字段，避免自由文本难以程序化处理\nclass Intent(BaseModel):\n    \"\"\"意图分类\"\"\"\n# 类别限定为枚举值，模型只能从中选，降低误分类概率\n    category: Literal[\"presale\", \"aftersale\", \"logistics\", \"complaint\", \"other\"]\n# 置信度字段用于后续低分兜底转人工，见下方路由判断\n    confidence: float\n\n# 第3步：意图识别路由 —— 把用户消息分类，决定走哪个处理分支\n# 分类任务简单，用小模型省成本，不必上大模型\ndef route_intent(message: str) -> str:\n    \"\"\"意图识别路由\"\"\"\n# 调用模型做工具调用式分类：让模型填写 classify 的参数\n    resp = client.chat.completions.create(\n# 意图分类用便宜模型，任务简单，省钱又不掉精度\n        model=\"gpt-4o-mini\",  # 意图分类用便宜模型\n# 把用户原话传给模型，提示其完成分类任务\n        messages=[{\"role\": \"user\", \"content\": f\"分类用户意图: {message}\"}],\n# 用 function calling 把输出约束为结构化 JSON，方便程序解析\n        tools=[{\"type\": \"function\", \"function\": {\n            \"name\": \"classify\",\n            \"parameters\": Intent.model_json_schema()\n        }}],\n# 强制模型调用 classify，确保一定返回结构化意图\n        tool_choice={\"type\": \"function\", \"function\": {\"name\": \"classify\"}}\n    )\n# 第4步：解析模型返回的 JSON 为 Intent 对象，自动校验字段\n    intent = Intent.model_validate_json(\n        resp.choices[0].message.tool_calls[0].function.arguments\n    )\n    \n# 第5步：低置信度或投诉类直接转人工\n# 低置信度硬闯容易答错，兜底转人工更安全；投诉需人工安抚\n    if intent.confidence < 0.7 or intent.category == \"complaint\":\n        return \"transfer_human\"\n    return intent.category\n\n# ===== 客服主流程 =====\n# 第6步：对外主入口 —— 先路由，再按意图取上下文，最后生成回复\ndef customer_service(user_id: str, message: str, history: list) -> str:\n    \"\"\"客服 Agent 主入口\"\"\"\n    # 1. 意图路由\n    route = route_intent(message)\n    \n# 命中转人工分支，直接返回提示，不再调用大模型\n    if route == \"transfer_human\":\n        return \"正在为您转接人工客服...\"\n    \n    # 2. 根据意图选择处理方式\n# 按意图取上下文：售前走 RAG，售后查订单，物流查物流\n    if route == \"presale\":\n        context = rag_search(message)  # RAG 检索商品知识\n    elif route == \"aftersale\":\n        context = query_order(user_id)  # 查询订单\n    elif route == \"logistics\":\n        context = query_logistics(user_id)  # 查询物流\n    \n    # 3. 生成回答\n# 生成回答：拼系统提示与历史，约束模型基于已知信息作答\n    system = f\"\"\"你是电商客服。基于以下信息回答:\n    上下文: {context}\n    规则: 不确定时转人工，不承诺未标注的优惠\"\"\"\n    \n# 组装对话：系统提示 + 历史 + 当前问题，保留多轮上下文\n    messages = [{\"role\": \"system\", \"content\": system}] + history + [{\"role\": \"user\", \"content\": message}]\n# 用更强模型生成最终回复，temperature 调低保证回答稳定\n    resp = client.chat.completions.create(model=\"gpt-4o\", messages=messages, temperature=0.3)\n# 返回模型生成的客服回复文本\n    return resp.choices[0].message.content","output":"用户: 我的订单什么时候到？\n→ 意图: logistics (conf=0.95)\n→ 查询物流 API\n→ 回答: 您的订单正在派送中，预计今天下午送达。"}}]}],"enterpriseCase":{"title":"电商客服 Agent 完整架构","background":"某电商平台日均 10 万咨询量，人工客服 200 人。","architecture":"意图路由 + RAG 知识库 + 订单/物流系统集成 + 情感识别转人工。","outcome":"自动回复率 78%，人工减少 60%，满意度 4.6/5。","lessons":"1) 意图路由是客服系统的核心；2) 情感识别比关键词更准确判断是否转人工；3) RAG 知识库要持续更新。"},"exercises":[{"title":"实现客服 Agent","description":"实现带意图路由和知识库的客服 Agent。","hints":"先实现意图分类，再加 RAG"}],"resources":[{"type":"course","title":"DeepLearning.AI 客服课程","url":"https://www.deeplearning.ai/"}],"quiz":["ch5-5.1-q1"]},{"id":"5.2","title":"代码助手与代码审查","subtitle":"开发代码相关 Agent","estimatedMinutes":30,"difficulty":4,"objectives":["掌握代码理解与 AST 解析","实现 PR Review 自动化","生成测试代码"],"content":[{"type":"knowledgePoint","title":"代码审查 Agent","content":[{"type":"code","data":{"filename":"code_review_agent.py","language":"python","title":"GitHub PR 自动审查 Agent","highlightLines":[19,22,23,26,27,29,30,32,34,35,37,39,40],"code":"# ===== 依赖与导入 =====\n# ast 做静态分析，openai 调用大模型做深度审查\nimport ast\nimport os\nfrom openai import OpenAI\n\n# ===================== 配置区（请自行填写，或设置环境变量）=====================\n# 方式一（推荐）：在终端先设置环境变量，再运行本脚本\n#   export OPENAI_API_KEY=\"sk-你的密钥\"\n#   export OPENAI_BASE_URL=\"https://api.openai.com/v1\"   # 官方地址，或任意兼容 OpenAI 的中转地址\n#   export OPENAI_MODEL=\"gpt-4o\"\n# 方式二（仅本地测试，切勿提交到 Git）：直接把下面的值改成你的真实信息\n# 第1步：加载配置 —— 优先读环境变量，避免密钥硬编码进代码\n# 缺失时回退占位值，保证脚本先能跑通再填真实信息\nOPENAI_API_KEY = os.getenv(\"OPENAI_API_KEY\", \"sk-在此填入你的API密钥\")\nOPENAI_BASE_URL = os.getenv(\"OPENAI_BASE_URL\", \"https://api.openai.com/v1\")\nMODEL = os.getenv(\"OPENAI_MODEL\", \"gpt-4o\")  # ← 模型名称，按需替换（如 gpt-4o-mini）\n\n\n# 第2步：创建 OpenAI 客户端 —— 复用同一实例发请求，省去重复初始化\n# base_url 支持官方或兼容中转，方便切换不同供应商\nclient = OpenAI(api_key=OPENAI_API_KEY, base_url=OPENAI_BASE_URL)\n\n# ===== 代码审查主流程 =====\n# 第3步：定义审查入口 —— 先做静态分析，再交给大模型深度审查\ndef review_pr(diff: str, file_path: str) -> dict:\n    \"\"\"审查 PR 代码变更\"\"\"\n# 1. 基础静态分析：用 ast 解析语法树，找出明显规范问题\n    # 1. 基础静态分析\n    issues = []\n# 用 try 包裹解析，遇到语法错误直接记为问题而非崩溃\n    try:\n# 把 diff 文本解析成抽象语法树，便于按节点检查\n        tree = ast.parse(diff)\n        for node in ast.walk(tree):\n# 遍历所有节点，只挑出函数定义进行审查\n            if isinstance(node, ast.FunctionDef):\n# 缺返回类型注解时给出建议，提升可读性与类型安全\n                if not node.returns:  # 缺少返回类型\n                    issues.append(f\"{node.name}: 建议添加返回类型注解\")\n# 参数过多提示拆分函数，降低复杂度与出错概率\n                if len(node.args.args) > 5:  # 参数过多\n                    issues.append(f\"{node.name}: 参数过多({len(node.args.args)})\")\n    except SyntaxError:\n        issues.append(\"语法错误\")\n    \n# 2. LLM 深度审查：把代码与审查要点交给大模型找深层问题\n    # 2. LLM 深度审查\n    review_prompt = f\"\"\"审查以下代码变更，关注:\n    1. 安全漏洞（SQL注入/XSS/命令注入）\n    2. 性能问题（N+1查询/内存泄漏）\n    3. 代码质量（命名/复杂度/重复）\n    4. 最佳实践\n    \n    文件: {file_path}\n    代码: {diff}\n    \n    输出 JSON: {{\"issues\": [...], \"score\": 0-10, \"summary\": \"...\"}}\"\"\"\n    \n# 第4步：调用大模型审查 —— 用 json_object 模式拿结构化结果\n# temperature=0 让结果更稳定，便于程序解析\n    resp = client.chat.completions.create(\n        model=MODEL,\n        messages=[{\"role\": \"user\", \"content\": review_prompt}],\n        response_format={\"type\": \"json_object\"},\n        temperature=0\n    )\n    \n# 导入 json 解析大模型返回的审查结果\n    import json\n# 把模型输出解析为字典，得到问题、评分与总结\n    result = json.loads(resp.choices[0].message.content)\n# 合并静态分析结果与模型结果，一并返回\n    result[\"static_issues\"] = issues\n    return result","output":"审查结果:\n  静态分析: 2 个问题\n  LLM 审查: 安全1个, 性能1个, 质量2个\n  评分: 7/10\n  摘要: 代码整体可接受，建议修复安全问题..."}}]}],"enterpriseCase":{"title":"GitHub PR 自动审查","background":"某团队每天 50+ PR 需要审查，人工审查耗时且标准不一。","architecture":"GitHub Webhook 触发 Agent → AST + LLM 双重审查 → 评论到 PR。","outcome":"PR 审查时间从 2 小时降至 5 分钟，缺陷发现率提升 35%。","lessons":"1) 静态分析 + LLM 结合比纯 LLM 更可靠；2) 审查结果要可操作（给出修复建议）；3) 避免过度审查引起开发者反感。"},"exercises":[{"title":"实现代码审查 Agent","description":"实现一个能审查 Python 代码安全和质量的 Agent。","hints":"用 AST 做静态分析 + LLM 做深度审查"}],"resources":[{"type":"tool","title":"CodeRabbit","url":"https://coderabbit.ai/","note":"AI 代码审查工具参考"}],"quiz":[]},{"id":"5.3","title":"数据分析 Agent","subtitle":"自然语言数据查询","estimatedMinutes":30,"difficulty":3,"objectives":["掌握 NL2SQL 技术","实现 Pandas 集成","生成数据可视化"],"content":[{"type":"knowledgePoint","title":"NL2SQL 实现","content":[{"type":"code","data":{"filename":"data_analysis_agent.py","language":"python","title":"数据分析 Agent (NL2SQL)","highlightLines":[24,27,29,31,33,34,35,37,38,39],"code":"# ===== 依赖与导入 =====\n# pandas 读结果，sqlite3 连库，openai 做 NL2SQL 与解读\nimport pandas as pd\nimport sqlite3\nimport os\nfrom openai import OpenAI\n\n# ===================== 配置区（请自行填写，或设置环境变量）=====================\n# 方式一（推荐）：在终端先设置环境变量，再运行本脚本\n#   export OPENAI_API_KEY=\"sk-你的密钥\"\n#   export OPENAI_BASE_URL=\"https://api.openai.com/v1\"   # 官方地址，或任意兼容 OpenAI 的中转地址\n#   export OPENAI_MODEL=\"gpt-4o\"\n# 方式二（仅本地测试，切勿提交到 Git）：直接把下面的值改成你的真实信息\n# 第1步：加载配置 —— 优先读环境变量，避免密钥硬编码进代码\n# 缺失时回退占位值，保证脚本先能跑通再填真实信息\nOPENAI_API_KEY = os.getenv(\"OPENAI_API_KEY\", \"sk-在此填入你的API密钥\")\nOPENAI_BASE_URL = os.getenv(\"OPENAI_BASE_URL\", \"https://api.openai.com/v1\")\nMODEL = os.getenv(\"OPENAI_MODEL\", \"gpt-4o\")  # ← 模型名称，按需替换（如 gpt-4o-mini）\n\n\n# 第2步：创建 OpenAI 客户端 —— 复用同一实例发请求，省去重复初始化\n# base_url 支持官方或兼容中转，方便切换不同供应商\nclient = OpenAI(api_key=OPENAI_API_KEY, base_url=OPENAI_BASE_URL)\n\n# ===== 数据分析 Agent =====\n# 第3步：封装数据库与模型能力，提供自然语言问答入口\nclass DataAgent:\n# 初始化时连接数据库，并预取 schema 供后续生成 SQL 参考\n    def __init__(self, db_path: str):\n# 只读连接业务库，避免 Agent 误改数据\n        self.conn = sqlite3.connect(db_path)\n# 获取 schema 供 LLM 参考，让生成的 SQL 字段名更准确\n        # 获取 schema 供 LLM 参考\n        self.schema = self._get_schema()\n    \n# 查询 sqlite_master 拿到建表语句，拼成 schema 文本\n    def _get_schema(self) -> str:\n        \"\"\"获取数据库 schema\"\"\"\n        cursor = self.conn.cursor()\n        cursor.execute(\"SELECT sql FROM sqlite_master WHERE type='table'\")\n        return \"\\n\".join([row[0] for row in cursor.fetchall()])\n    \n# ===== 问答主流程 =====\n# 第4步：自然语言查询 —— NL2SQL、执行、分析、可视化的四步流水线\n    def ask(self, question: str) -> dict:\n        \"\"\"自然语言查询数据\"\"\"\n        # 1. NL2SQL: 自然语言转 SQL\n# 1. NL2SQL：把自然语言问题转成 SQL 语句\n        sql = self._nl_to_sql(question)\n        # 2. 执行 SQL（只读，安全限制）\n# 2. 执行 SQL（只读，安全限制）：只 SELECT 不改动数据\n        df = pd.read_sql(sql, self.conn)\n        # 3. 用 LLM 分析结果\n# 3. 用 LLM 分析结果：把表格翻译成人话结论\n        analysis = self._analyze(question, df)\n        # 4. 生成可视化建议\n# 4. 生成可视化建议：告诉前端该画什么图\n        viz = self._suggest_viz(df)\n        return {\"sql\": sql, \"data\": df.to_dict(), \"analysis\": analysis, \"viz\": viz}\n    \n# ===== NL2SQL 实现 =====\n# 第5步：拼接 schema 与问题，让模型产出仅查询的 SQL\n    def _nl_to_sql(self, question: str) -> str:\n        prompt = f\"\"\"数据库 schema: {self.schema}\n        将以下问题转为 SQL（仅 SELECT，禁止修改数据）:\n        问题: {question}\n        SQL:\"\"\"\n# 调用模型生成 SQL，temperature=0 保证输出稳定可解析\n        resp = client.chat.completions.create(\n            model=MODEL, messages=[{\"role\": \"user\", \"content\": prompt}], temperature=0\n        )\n# 去掉模型可能带回的 markdown 代码围栏，拿到纯净 SQL\n        return resp.choices[0].message.content.strip('```sql').strip('```').strip()","output":"问题: 上个月销量最高的5个商品\nSQL: SELECT product_name, SUM(quantity) as total FROM orders WHERE date >= date('now', '-1 month') GROUP BY product_name ORDER BY total DESC LIMIT 5\n\n分析: 上月销量最高的是商品A(1200件)，其次是商品B(980件)...\n可视化建议: 柱状图"}}]},{"type":"callout","variant":"danger","title":"NL2SQL 安全","text":"NL2SQL 必须限制为只读（仅 SELECT），禁止 DROP/DELETE/UPDATE。建议：1) 用只读数据库账号；2) SQL 白名单校验；3) 限制查询行数和超时。"}],"enterpriseCase":{"title":"BI 数据分析 Agent","background":"某公司业务人员需要查询数据但不会 SQL。","architecture":"NL2SQL + Pandas 分析 + 自动可视化 + LLM 洞察生成。","outcome":"业务人员自助查询率 80%，分析师从取数工作中解放。","lessons":"1) schema 描述质量决定 NL2SQL 准确率；2) 只读安全限制必须严格；3) 自动可视化大幅提升体验。"},"exercises":[{"title":"实现 NL2SQL Agent","description":"实现一个能将自然语言转 SQL 并查询的 Agent。","hints":"先获取 schema，再让 LLM 生成 SQL"}],"resources":[{"type":"tool","title":"Vanna.ai","url":"https://vanna.ai/","note":"开源 NL2SQL"},{"type":"tool","title":"PandasAI","url":"https://pandas-ai.com/"}],"quiz":["ch5-5.3-q1"]},{"id":"5.4","title":"自动化运营 Agent","subtitle":"运营自动化","estimatedMinutes":25,"difficulty":3,"objectives":["设计工作流自动化","实现定时任务与触发器","多渠道通知"],"content":[{"type":"knowledgePoint","title":"自动化运营架构","content":[{"type":"paragraph","text":"自动化运营 Agent 结合定时触发、数据监控、内容生成、多渠道通知，实现运营流程自动化。"},{"type":"code","data":{"filename":"ops_agent.py","language":"python","title":"定时报告生成 Agent","code":"# ===== 依赖与导入 =====\n# schedule 定时，openai 生成报告，os 读配置\nimport schedule\nimport time\nimport os\nfrom openai import OpenAI\n\n# ===================== 配置区（请自行填写，或设置环境变量）=====================\n# 方式一（推荐）：在终端先设置环境变量，再运行本脚本\n#   export OPENAI_API_KEY=\"sk-你的密钥\"\n#   export OPENAI_BASE_URL=\"https://api.openai.com/v1\"   # 官方地址，或任意兼容 OpenAI 的中转地址\n#   export OPENAI_MODEL=\"gpt-4o\"\n# 方式二（仅本地测试，切勿提交到 Git）：直接把下面的值改成你的真实信息\n# 第1步：加载配置 —— 优先读环境变量，避免密钥硬编码进代码\n# 缺失时回退占位值，保证脚本先能跑通再填真实信息\nOPENAI_API_KEY = os.getenv(\"OPENAI_API_KEY\", \"sk-在此填入你的API密钥\")\nOPENAI_BASE_URL = os.getenv(\"OPENAI_BASE_URL\", \"https://api.openai.com/v1\")\nMODEL = os.getenv(\"OPENAI_MODEL\", \"gpt-4o\")  # ← 模型名称，按需替换（如 gpt-4o-mini）\n\n\n# 第2步：创建 OpenAI 客户端 —— 复用同一实例发请求，省去重复初始化\n# base_url 支持官方或兼容中转，方便切换不同供应商\nclient = OpenAI(api_key=OPENAI_API_KEY, base_url=OPENAI_BASE_URL)\n\n# ===== 运营日报 Agent =====\n# 第3步：定时自动出报告 —— 取数、分析、发送、告警四步走\ndef daily_report_agent():\n    \"\"\"每日自动生成运营报告\"\"\"\n    # 1. 收集数据\n# 1. 收集数据：并行查核心指标，聚合成字典供模型使用\n    metrics = {\n        \"DAU\": query_dau(),\n        \"revenue\": query_revenue(),\n        \"churn\": query_churn_rate()\n    }\n    \n    # 2. LLM 分析并生成报告\n# 2. LLM 分析并生成报告：把指标交给模型写日报与建议\n    report = client.chat.completions.create(\n        model=MODEL,\n        messages=[{\"role\": \"user\", \"content\": f\"\"\"\n        基于以下数据生成运营日报:\n        DAU: {metrics['DAU']}\n        收入: {metrics['revenue']}\n        流失率: {metrics['churn']}\n        \n        输出: 关键指标+趋势分析+建议\"\"\"}],\n        temperature=0.3\n    ).choices[0].message.content\n    \n    # 3. 多渠道发送\n# 3. 多渠道发送：邮件与 Slack 同步触达团队\n    send_email(\"team@company.com\", \"运营日报\", report)\n    send_slack(\"#ops-channel\", report)\n    \n    # 4. 异常告警\n# 4. 异常告警：流失率超阈值时主动报警，及时干预\n    if metrics['churn'] > 0.05:\n        send_alert(f\"⚠️ 流失率异常: {metrics['churn']:.1%}\")\n\n# 每天早上 9 点执行\n# 注册定时任务：每天 9 点跑一次日报\nschedule.every().day.at(\"09:00\").do(daily_report_agent)\n# 主循环：每分钟检查一次是否有任务到点执行\nwhile True:\n# 到点则运行任务，否则睡眠让出 CPU\n    schedule.run_pending()\n    time.sleep(60)","output":"每日 09:00 自动执行:\n→ 收集 DAU/收入/流失率\n→ LLM 生成分析报告\n→ 邮件 + Slack 发送\n→ 异常时触发告警"}}]}],"enterpriseCase":{"title":"内容运营自动化","background":"某媒体公司需要自动生成和发布内容。","architecture":"Agent 定时生成内容 → 人工审核 → 自动发布到多平台。","outcome":"内容产出提升 3 倍，编辑聚焦审核而非创作。","lessons":"自动化必须保留人工审核环节，内容质量是底线。"},"exercises":[{"title":"实现定时报告 Agent","description":"实现一个每天定时生成并发送报告的 Agent。","hints":"用 schedule 库定时执行"}],"resources":[{"type":"doc","title":"n8n 自动化","url":"https://docs.n8n.io/"}],"quiz":[]},{"id":"5.5","title":"企业知识库问答","subtitle":"大规模企业 RAG 系统","estimatedMinutes":35,"difficulty":4,"objectives":["处理大规模文档","实现权限控制","增量索引更新"],"content":[{"type":"knowledgePoint","title":"企业知识库架构","content":[{"type":"table","data":{"headers":["挑战","解决方案"],"rows":[["数万+文档","分批索引 + 增量更新"],["权限控制","文档级 ACL + 查询时过滤"],["多格式支持","统一 Loader（PDF/Word/Confluence）"],["引用来源","检索时保留文档元数据"],["实时更新","Webhook 触发增量索引"]]}},{"type":"callout","variant":"info","title":"权限控制关键","text":"企业知识库必须实现文档级权限控制：用户只能检索到有权限的文档。方案：1) 向量库存 ACL 元数据；2) 检索后按权限过滤；3) 或按部门分库索引。"}]}],"enterpriseCase":{"title":"企业内部知识库","background":"某 5000 人企业，内部文档 2 万+，分布在 Confluence/SharePoint/本地。","architecture":"统一 Loader + 增量索引 + 文档级 ACL + 混合检索 + Reranker。","outcome":"员工找文档时间从 15 分钟降至 30 秒，知识复用率提升 50%。","lessons":"1) 权限控制是企业 RAG 的硬需求；2) 增量索引避免全量重建；3) 引用来源提升可信度。"},"exercises":[{"title":"搭建带权限的 RAG","description":"实现一个带文档级权限控制的 RAG 系统。","hints":"在向量元数据中存储 ACL，检索后过滤"}],"resources":[{"type":"doc","title":"LlamaIndex 企业级 RAG","url":"https://docs.llamaindex.ai/"}],"quiz":[]},{"id":"5.6","title":"多 Agent 协作开发系统","subtitle":"多 Agent 软件开发","estimatedMinutes":35,"difficulty":5,"objectives":["设计软件开发多 Agent","实现角色协作","管理代码版本"],"content":[{"type":"knowledgePoint","title":"多 Agent 开发架构","content":[{"type":"mermaid","data":{"title":"多 Agent 软件开发系统","code":"flowchart LR\n  P[PM Agent\n需求分析] --> D[Designer Agent\n架构设计]\n  D --> C1[Coder Agent 1\n后端开发]\n  D --> C2[Coder Agent 2\n前端开发]\n  C1 --> T[Tester Agent\n测试验证]\n  C2 --> T\n  T --> R[Reviewer Agent\n代码审查]\n  R -->|通过| DEPLOY[部署]\n  R -->|不通过| C1"}},{"type":"code","data":{"filename":"multi_agent_dev.py","language":"python","title":"CrewAI 多 Agent 协作开发","code":"# ===== 依赖与导入 =====\n# 使用 crewAI 的多智能体协作框架\nimport os\nfrom crewai import Agent, Task, Crew, Process\n\n# 第1步：定义角色 Agent —— 每个角色有目标、背景与指定模型\n# 产品经理、开发者、测试各司其职，分工协作\npm = Agent(role='产品经理', goal='分析需求并制定开发计划',\n           backstory='资深 PM，擅长需求分解', llm='gpt-5')\ncoder = Agent(role='全栈开发者', goal='编写高质量代码',\n             backstory='10年经验全栈工程师', llm='gpt-5')\ntester = Agent(role='测试工程师', goal='验证代码质量',\n               backstory='严谨的测试专家', llm='gpt-5')\n\n# 第2步：拆任务 Task —— 为每个 Agent 指派具体任务\n# context 串联上下游，后一步可参考前一步产物\nplan = Task(description='分析需求: {req}，输出开发计划', agent=pm)\ncode = Task(description='根据计划编写代码', agent=coder, context=[plan])\ntest = Task(description='测试代码功能和质量', agent=tester, context=[code])\n\n# 第3步：组建 Crew 并按顺序执行 —— 串行流程保证依赖顺序\n# 先计划、再写码、最后测试，结果逐层传递\ncrew = Crew(agents=[pm, coder, tester], tasks=[plan, code, test],\n            process=Process.sequential)\n# 第4步：启动协作 —— 传入需求，自动跑完整条开发流水线\nresult = crew.kickoff(inputs={'req': '开发一个 TODO API'})","output":"PM: 需求分解为5个API端点\nCoder: 编写 FastAPI 代码\ntester: 测试通过，覆盖率85%"}}]}],"enterpriseCase":{"title":"多 Agent 协作开发系统","background":"某创业公司用多 Agent 自动开发小型项目。","architecture":"PM/Designer/Coder/Tester/Reviewer 5 Agent 流水线。","outcome":"小型项目自动开发率 70%，开发周期缩短 60%。","lessons":"1) 复杂项目仍需人工参与；2) Agent 间代码交接是难点；3) 适合 MVP 和原型开发。"},"exercises":[{"title":"用 CrewAI 实现 3 Agent 协作","description":"实现 PM/Coder/Tester 三个 Agent 的协作开发流程。","hints":"用 Process.sequential 顺序执行"}],"resources":[{"type":"tool","title":"ChatDev","url":"https://github.com/OpenBMB/ChatDev"},{"type":"tool","title":"MetaGPT","url":"https://github.com/FoundationAgents/MetaGPT"}],"quiz":[]},{"id":"5.7","title":"全栈开发 Agent","subtitle":"端到端开发能力","estimatedMinutes":30,"difficulty":5,"objectives":["设计全栈 Agent 架构","理解服务化部署","端到端测试"],"content":[{"type":"knowledgePoint","title":"全栈 Agent 架构","content":[{"type":"paragraph","text":"全栈开发 Agent 能独立完成从需求分析到部署的完整流程：后端 API（FastAPI）+ 数据库（SQL）+ 前端 + 测试 + 部署。"},{"type":"callout","variant":"info","title":"参考：Devin","text":"Devin 是 Cognition 推出的首个 AI 软件工程师，能独立完成完整开发任务。开源替代有 OpenDevin。当前能力适合中小型项目，大型项目仍需人类主导。"}]}],"enterpriseCase":{"title":"全栈开发 Agent 系统","background":"用 Agent 自动开发一个 CRUD API 服务。","architecture":"Agent 自主完成：数据库设计 → API 开发 → 单元测试 → Docker 部署。","outcome":"简单 CRUD 项目 30 分钟内完成开发和部署。","lessons":"1) 适合标准化项目；2) 复杂业务逻辑需人工指导；3) 自动测试是质量保障关键。"},"exercises":[{"title":"设计全栈 Agent 架构","description":"设计一个能开发 FastAPI + SQLite + 前端的 Agent 系统架构。","hints":"参考 Devin 的架构设计"}],"resources":[{"type":"tool","title":"OpenDevin","url":"https://github.com/OpenDevin/OpenDevin"}],"quiz":[]},{"id":"5.8","title":"部署与性能优化","subtitle":"生产级部署与优化","estimatedMinutes":30,"difficulty":4,"objectives":["掌握 FastAPI 服务化","Docker 容器化部署","性能优化策略"],"content":[{"type":"knowledgePoint","title":"FastAPI 服务化","content":[{"type":"code","data":{"filename":"fastapi_agent.py","language":"python","title":"FastAPI Agent 服务","highlightLines":[13,14,15,16,19,20,22,24],"code":"# ===== 依赖与导入 =====\n# FastAPI 提供接口，uvicorn 负责运行服务\nimport os\nfrom fastapi import FastAPI\nfrom pydantic import BaseModel\nimport uvicorn\n\n# 第1步：创建 FastAPI 应用实例 —— 后续接口都挂在这个 app 上\napp = FastAPI(title=\"Agent API\")\n\n# ===== 请求模型 =====\n# 用 Pydantic 定义入参结构，自动校验类型与必填项\nclass Query(BaseModel):\n    message: str\n    session_id: str = None\n\n# 第2步：定义对话接口 —— 异步端点避免阻塞其他请求\n# Agent 调用耗时长，异步让服务在等待时仍能处理别的请求\n@app.post(\"/chat\")\nasync def chat(query: Query):\n# 接口说明：对外暴露的 Agent 对话入口\n    \"\"\"Agent 对话接口\"\"\"\n# 异步调用 Agent，等待其返回结果后再响应\n    result = await agent.run(query.message, query.session_id)\n    return {\"response\": result}\n\n# 健康检查接口：供负载均衡探活，确认服务存活\n@app.get(\"/health\")\nasync def health():\n    return {\"status\": \"ok\"}\n\n# 第3步：启动服务 —— 监听 0.0.0.0:8000 对外提供访问\nif __name__ == \"__main__\":\n    uvicorn.run(app, host=\"0.0.0.0\", port=8000)","output":"API 文档: http://localhost:8000/docs\n对话接口: POST /chat\n健康检查: GET /health"}},{"type":"code","data":{"filename":"Dockerfile","language":"text","title":"Docker 部署","code":"# 基础镜像：精简版 Python 3.12，体积小、启动快\nFROM python:3.12-slim\n\n# 设定工作目录为 /app，后续命令都在此目录执行\nWORKDIR /app\n# 先拷贝依赖清单，利用镜像层缓存加速后续构建\nCOPY requirements.txt .\n# 安装依赖并禁用缓存，减小最终镜像体积\nRUN pip install --no-cache-dir -r requirements.txt\n\n# 拷贝全部应用代码到工作目录\nCOPY . .\n# 声明容器对外暴露 8000 端口\nEXPOSE 8000\n# 启动命令：用 uvicorn 拉起应用，绑定 0.0.0.0 监听 8000\nCMD [\"uvicorn\", \"main:app\", \"--host\", \"0.0.0.0\", \"--port\", \"8000\"]","output":""}}]},{"type":"knowledgePoint","title":"性能优化策略","content":[{"type":"table","data":{"headers":["策略","效果","实现"],"rows":[["**Embedding 缓存**","减少 90% 向量化成本","缓存 query→embedding 映射"],["**响应缓存**","重复问题零延迟","缓存 query→answer"],["**模型分级**","降低 60% 成本","简单任务用 mini 模型"],["**流式输出**","首字延迟降 80%","stream=True"],["**并发处理**","吞吐量提升 5 倍","asyncio.gather"],["**限流降级**","保护系统稳定","令牌桶 + 熔断"]]}},{"type":"callout","variant":"tip","title":"成本控制","text":"生产 Agent 成本控制核心：1) 简单任务用 GPT-5-mini（成本 1/16）；2) 缓存 Embedding 和高频问答；3) 限制 max_steps 和 max_tokens；4) 监控每日 Token 消耗设上限。"}]}],"enterpriseCase":{"title":"Agent 服务高可用部署","background":"某公司 Agent 需支撑日均 10 万次调用。","architecture":"FastAPI + Docker + Nginx 负载均衡 + Redis 缓存 + 多实例水平扩展。","outcome":"QPS 500+，P99 延迟 <5s，可用性 99.9%。","lessons":"1) 状态外置（Redis）才能水平扩展；2) 缓存是成本和性能的关键；3) 限流降级保护系统稳定。"},"exercises":[{"title":"设计部署方案","description":"为一个 Agent 服务设计高可用部署方案。","hints":"考虑负载均衡、缓存、监控"}],"resources":[{"type":"doc","title":"FastAPI 部署","url":"https://fastapi.tiangolo.com/deployment/"},{"type":"doc","title":"Docker 文档","url":"https://docs.docker.com/"}],"quiz":["ch5-5.8-q1"]},{"id":"5.9","title":"安全与合规","subtitle":"设计安全的 Agent 系统","estimatedMinutes":25,"difficulty":4,"objectives":["设计 Guardrail","实现工具权限最小化","理解数据隐私合规"],"content":[{"type":"knowledgePoint","title":"Agent 安全防护体系","content":[{"type":"table","data":{"headers":["层面","措施","实现"],"rows":[["**输入安全**","Prompt 注入防护","输入过滤 + 边界标注"],["**工具安全**","权限最小化","只授予必要工具 + HITL"],["**输出安全**","内容审查","敏感信息脱敏 + 违规检测"],["**数据安全**","隐私保护","数据加密 + GDPR/PIPL 合规"],["**审计安全**","可追溯","全链路日志 + 审计追踪"]]}},{"type":"callout","variant":"danger","title":"合规要点","text":"**GDPR（欧盟）**：数据可删除权、数据可携带权。**PIPL（中国个人信息保护法）**：告知同意、最小必要。**金融**：交易审计、风险提示。**医疗**：数据脱敏、诊断不替代医生。"}]}],"enterpriseCase":{"title":"金融 Agent 合规设计","background":"某银行 Agent 需通过银监会安全审查。","architecture":"五层安全：输入过滤 + Guardrail + HITL + 审计日志 + 数据脱敏。","outcome":"通过安全审查，零合规事故。","lessons":"金融/医疗/法律场景安全合规是第一优先级。"},"exercises":[{"title":"设计安全方案","description":"为客服 Agent 设计完整的安全防护方案。","hints":"覆盖输入/工具/输出/数据/审计五层"}],"resources":[{"type":"doc","title":"OWASP LLM Top 10","url":"https://owasp.org/www-project-top-10-for-large-language-model-applications/"}],"quiz":["ch5-5.9-q1"]},{"id":"5.10","title":"避坑指南与常见难点","subtitle":"避免常见陷阱","estimatedMinutes":30,"difficulty":3,"objectives":["避免异步编程陷阱","解决 Pydantic 校验问题","防止 Agent 循环失控"],"content":[{"type":"knowledgePoint","title":"五大常见难点","content":[{"type":"table","data":{"headers":["难点","表现","解决方案"],"rows":[["**异步编程**","async/sync 混用报错","统一用 async，同步库用 run_in_executor"],["**Pydantic 校验**","LLM 输出不稳定导致校验失败","重试机制 + 错误反馈给 LLM 修正"],["**依赖冲突**","包版本不兼容","用 uv/poetry 管理依赖，锁定版本"],["**循环失控**","Agent 无限循环 Token 爆炸","max_steps + 超时 + 费用上限"],["**类型系统**","动态类型导致运行时错误","强制类型注解 + mypy 检查"]]}},{"type":"callout","variant":"note","title":"9 条避坑原则","text":"1) 先跑通再优化；2) 生成用 4o-mini，推理用 4o；3) 永远设 max_steps；4) 工具调用必须错误处理；5) 缓存 Embedding；6) 异步统一；7) Prompt 与代码分离；8) 接入可观测性；9) 安全多层防御。"}]}],"enterpriseCase":{"title":"生产事故复盘","background":"某公司 Agent 因未设 max_steps 导致 Token 爆炸，单次请求消耗 $50。","architecture":"增加 max_steps=15 + Token 上限 50K + 费用上限 $1 + 告警。","outcome":"后续零类似事故。","lessons":"防护措施必须上线前就位，不能事后补救。"},"exercises":[{"title":"编写最佳实践 Checklist","description":"为 Agent 项目编写一份上线前最佳实践 checklist。","hints":"覆盖安全、性能、成本、可观测性"}],"resources":[{"type":"doc","title":"Python 异步编程","url":"https://docs.python.org/3/library/asyncio.html"}],"quiz":["ch5-5.10-q1"]}]};

  // chapter-6.json (13.2KB)
  window.__DATA__ = window.__DATA__ || {};
  window.__DATA__["CHAPTER_6_DATA"] = {"id":"ch6","number":6,"title":"前沿趋势展望","subtitle":"建立前瞻视角，把握 Agent 技术发展方向","estimatedHours":10,"difficulty":2,"sections":[{"id":"6.1","title":"Agent OS 与 Agent 操作系统","subtitle":"理解 Agent OS 愿景","estimatedMinutes":15,"difficulty":3,"objectives":["理解 Agent OS 概念","了解探索项目","理解对开发者的意义"],"content":[{"type":"knowledgePoint","title":"Agent OS 概念","content":[{"type":"paragraph","text":"**Agent OS** 是为 AI Agent 提供标准化运行环境的操作系统，类似传统 OS 对应用程序的作用。它管理 Agent 的资源（模型、工具、数据）、调度（任务队列）、通信（Agent 间消息）、安全（权限隔离）。"},{"type":"table","data":{"headers":["项目","机构","特点"],"rows":[["**AIOS**","Rutgers University","学术原型，Agent 调度与资源管理"],["**AgentOS**","开源社区","模块化 Agent 运行时"],["**Microsoft Agent Framework**","微软","统一多 Agent 运行时（AutoGen 进入维护模式）"]]}},{"type":"callout","variant":"tip","title":"2026 现实：编码 Agent 即「软件 Agent OS」","text":"2026 年最落地的 Agent OS 形态是 agentic 编码平台：Claude Code（终端优先、可并行子 Agent）、OpenAI Codex（云端沙箱、异步并行任务）、Google Antigravity（Google 的 agentic 开发平台，搭配 Gemini 3.5）。它们统一了「模型 + 工具 + 沙箱 + 文件系统 + 多 Agent 编排」，让 Agent 在受控环境中自主写代码、跑命令、修 Bug。"},{"type":"callout","variant":"info","title":"与传统 OS 的差异","text":"传统 OS 管理 CPU/内存/磁盘等物理资源；Agent OS 管理模型/工具/数据等 AI 资源。Agent OS 还需处理概率性执行、自然语言接口等新挑战。"}]}],"exercises":[{"title":"调研 Agent OS 项目","description":"调研 AIOS 或 AgentOS 项目，总结其架构和特点。","hints":"关注资源管理和调度机制"}],"resources":[{"type":"paper","title":"AIOS: AI Agent Operating System","url":"https://arxiv.org/abs/2403.16971"}],"quiz":["ch6-6.1-q1"]},{"id":"6.2","title":"具身智能与物理 Agent","subtitle":"机器人 + LLM","estimatedMinutes":15,"difficulty":2,"objectives":["了解具身智能概念","理解机器人+LLM 结合","了解代表项目"],"content":[{"type":"knowledgePoint","title":"具身智能（Embodied AI）","content":[{"type":"paragraph","text":"**具身智能**是将 LLM 的推理能力与物理机器人的感知执行能力结合，让 AI 能在物理世界中行动。这是从数字 Agent 到物理 Agent 的跨越。"},{"type":"table","data":{"headers":["项目","公司","特点"],"rows":[["**Figure 01/02**","Figure AI","人形机器人 + OpenAI 模型"],["**Optimus**","Tesla","人形机器人，自主任务执行"],["**RT-2**","Google DeepMind","视觉-语言-动作模型"],["**GR-1**","字节跳动","人形机器人通用模型"]]}},{"type":"callout","variant":"tip","title":"Sim-to-Real","text":"具身智能核心挑战是 Sim-to-Real（仿真到现实）：在仿真环境中训练，迁移到真实世界。差距（reality gap）是主要难题。"}]}],"exercises":[{"title":"调研具身智能项目","description":"选择一个具身智能项目深入调研。","hints":"关注感知-决策-执行链路"}],"resources":[{"type":"paper","title":"RT-2: Vision-Language-Action Models","url":"https://robotics-transformer2.github.io/"}],"quiz":[]},{"id":"6.3","title":"AGI 路线与 Agent 演进","subtitle":"Agent 在 AGI 路径中的位置","estimatedMinutes":15,"difficulty":3,"objectives":["理解 AGI 概念","了解自主性等级","认识 Agent 与 AGI 的差距"],"content":[{"type":"knowledgePoint","title":"AGI 与 Agent 演进","content":[{"type":"paragraph","text":"**AGI（通用人工智能）** 指能像人类一样在各种任务中表现出智能的 AI。Agent 是通往 AGI 的重要路径——从任务特定到任务通用。"},{"type":"table","data":{"headers":["等级","名称","描述","当前状态"],"rows":[["**L1**","工具型","人工指定工具调用","✅ 已实现"],["**L2**","任务型","给定任务自主完成","✅ 已实现"],["**L3**","自主型","给定大目标自主分解执行","⚠️ 部分实现"],["**L4**","自适应型","能学习适应新领域","🔬 研究中"],["**L5**","通用型","AGI，跨领域通用","❌ 未实现"]]}},{"type":"callout","variant":"note","title":"当前水平","text":"当前最好的 Agent 系统约在 L2-L3 之间。从 L3 到 L4（自适应学习）和 L4 到 L5（通用智能）仍有巨大差距，可能需要新的技术突破。"}]}],"exercises":[{"title":"绘制自主性演进图","description":"绘制 Agent 自主性 L1-L5 演进图，标注当前技术水平。","hints":"参考等级表"}],"resources":[{"type":"paper","title":"Levels of AGI","url":"https://arxiv.org/abs/2311.17824"}],"quiz":["ch6-6.3-q1"]},{"id":"6.4","title":"多模态 Agent","subtitle":"视觉/语音/视频理解","estimatedMinutes":15,"difficulty":2,"objectives":["了解多模态 Agent 能力","理解多模态工具调用","了解多模态 RAG"],"content":[{"type":"knowledgePoint","title":"多模态 Agent 能力","content":[{"type":"table","data":{"headers":["模态","能力","代表模型","应用场景"],"rows":[["**视觉**","理解图片/截图","GPT-5, Claude Opus 4.8","UI 分析、图表理解"],["**语音**","语音对话","GPT-5 Voice","语音助手、实时翻译"],["**视频**","理解视频内容","Gemini 3.5","视频分析、监控"],["**多模态工具**","调用视觉/语音工具","Computer Use","GUI 操作、文档处理"]]}},{"type":"callout","variant":"info","title":"多模态 RAG","text":"多模态 RAG 不仅能检索文本，还能检索图片、表格、视频片段。例如：查询产品手册时，同时返回相关文字说明和操作示意图。"}]}],"exercises":[{"title":"体验多模态 Agent","description":"体验 GPT-5 的视觉能力，分析一张架构图。","hints":"上传图片让 Agent 解释"}],"resources":[{"type":"doc","title":"GPT-5 多模态","url":"https://platform.openai.com/docs/guides/vision"}],"quiz":[]},{"id":"6.5","title":"Agent 安全与对齐","subtitle":"AI 安全挑战","estimatedMinutes":15,"difficulty":3,"objectives":["理解对齐问题","了解 RLHF 技术","认识 Agent 安全风险"],"content":[{"type":"knowledgePoint","title":"AI 对齐与安全","content":[{"type":"paragraph","text":"**对齐问题（Alignment Problem）** 是确保 AI 行为符合人类价值观的核心挑战。Agent 因为能执行实际操作，安全风险比纯文本 LLM 更大。"},{"type":"table","data":{"headers":["安全风险","说明","研究方向"],"rows":[["**目标误解**","Agent 误解用户意图","意图澄清、确认机制"],["**工具滥用**","Agent 滥用工具权限","权限最小化、HITL"],["**欺骗行为**","Agent 为达目标欺骗用户","诚实性训练、可审计"],["**能力越界**","Agent 超出预期能力范围","能力监测、紧急停止"]]}},{"type":"callout","variant":"warning","title":"RLHF 与对齐","text":"**RLHF（基于人类反馈的强化学习）** 是当前主要的对齐技术：通过人类偏好数据训练奖励模型，引导 LLM 行为对齐人类价值观。但 RLHF 不完美，越狱攻击仍可能成功。"}]}],"exercises":[{"title":"设计安全评估方案","description":"为 Agent 设计安全评估方案，包含红队测试。","hints":"参考 OWASP LLM Top 10"}],"resources":[{"type":"doc","title":"Anthropic 安全研究","url":"https://www.anthropic.com/research"},{"type":"doc","title":"NIST AI 风险管理","url":"https://www.nist.gov/itl/ai-risk-management-framework"}],"quiz":["ch6-6.5-q1"]},{"id":"6.6","title":"Agent 经济与市场化","subtitle":"Agent 商业化方向","estimatedMinutes":15,"difficulty":2,"objectives":["了解 AgentaaS 模式","理解 Agent 市场","探索商业模式"],"content":[{"type":"knowledgePoint","title":"Agent 经济","content":[{"type":"paragraph","text":"随着 Agent 能力提升，Agent 正在形成新的经济形态：**Agent 即服务（AgentaaS）**、Agent 间交易市场、Agent 自主经济行为。"},{"type":"table","data":{"headers":["商业模式","说明","示例"],"rows":[["**AgentaaS**","Agent 作为云服务提供","OpenAI Agents SDK / 云厂商 Agent 服务"],["**按结果付费**","按任务完成效果收费","代码审查按 PR 收费"],["**Agent 市场**","Agent 交易和订阅平台","GPT Store、Coze 商店"],["**Agent 协作**","Agent 间委托任务并付费","自主 Agent 经济体"]]}},{"type":"callout","variant":"info","title":"未来展望","text":"未来可能出现 Agent 间自主交易的经济系统——Agent A 委托 Agent B 完成子任务并支付费用。这需要 Agent 身份认证、信誉系统、支付协议等基础设施。"}]}],"exercises":[{"title":"设计 Agent 商业模式","description":"为一个 Agent 产品设计商业模式。","hints":"考虑订阅/按调用/按结果三种模式"}],"resources":[{"type":"blog","title":"a16z AI 投资报告","url":"https://a16z.com/"}],"quiz":[]},{"id":"6.7","title":"开源生态动态","subtitle":"跟踪开源生态","estimatedMinutes":15,"difficulty":2,"objectives":["了解重要开源项目","跟踪开源模型","了解本地部署方案"],"content":[{"type":"knowledgePoint","title":"开源生态概览","content":[{"type":"table","data":{"headers":["类别","项目","特点"],"rows":[["**Agent 框架**","LangChain, LlamaIndex, CrewAI, AutoGen","持续迭代，生态丰富"],["**开源模型**","Llama 4, Qwen (最新版), DeepSeek V4","性能比肩闭源，可本地部署"],["**本地部署**","Ollama, vLLM, LM Studio","简化本地推理部署"],["**向量数据库**","Chroma, Qdrant, Milvus","开源 RAG 基础设施"],["**评估工具**","RAGAS, DeepEval, Promptfoo","Agent 质量评估"]]}},{"type":"callout","variant":"tip","title":"如何跟踪动态","text":"1) GitHub Trending（关注 AI/LLM 标签）；2) Hugging Face Trending；3) r/LocalLLaMA；4) LangChain/LlamaIndex Discord；5) ArXiv 每日论文。建议每周花 1 小时跟踪。"}]}],"exercises":[{"title":"关注开源项目","description":"在 GitHub 上关注 3 个 Agent 开源项目并跟踪更新。","hints":"Star 项目并开启 Release 通知"}],"resources":[{"type":"tool","title":"GitHub Trending","url":"https://github.com/trending"},{"type":"tool","title":"Hugging Face","url":"https://huggingface.co/"}],"quiz":[]},{"id":"6.8","title":"学习资源与社区","subtitle":"建立持续学习路径","estimatedMinutes":10,"difficulty":1,"objectives":["获取必读论文清单","了解在线课程","加入活跃社区"],"content":[{"type":"knowledgePoint","title":"持续学习资源","content":[{"type":"paragraph","text":"Agent 领域发展极快，持续学习是保持竞争力的关键。以下资源按优先级排序。"},{"type":"table","data":{"headers":["类别","资源","推荐"],"rows":[["**论文**","ReAct, ToT, Reflexion, GraphRAG","必读经典"],["**课程**","DeepLearning.AI 系列, Anthropic 官方","系统学习"],["**社区**","LangChain Discord, r/LocalLLaMA","实时交流"],["**博客**","Anthropic Blog, Lilian Weng, LangChain Blog","深度分析"],["**会议**","NeurIPS, ACL, ICML","前沿研究"],["**Newsletter**","The Batch, AI Tool Report","定期推送"]]}},{"type":"callout","variant":"note","title":"学习方法论","text":"1) **20%时间跟前沿**：每周读 1-2 篇论文/博客；2) **60%时间动手做**：每月完成 1 个小项目；3) **20%时间教别人**：写博客或分享。输入-实践-输出循环是最高效的学习方式。"}]}],"exercises":[{"title":"制定持续学习计划","description":"制定个人持续学习计划：每周/每月的学习目标。","hints":"参考 20-60-20 时间分配"}],"resources":[{"type":"course","title":"DeepLearning.AI 短课程","url":"https://www.deeplearning.ai/short-courses/"},{"type":"doc","title":"Anthropic 学习中心","url":"https://anthropic.com/news"}],"quiz":[]}]};

